type Primitive = string | number | boolean | null | undefined | symbol | bigint;
type FlatValue = Primitive | unknown[] | Date | RegExp | Function;
type NestedObject = { [key: string]: unknown };
type FlatObject = { [key: string]: FlatValue };

function isPlainObject(value: unknown): value is NestedObject {
  if (value === null || typeof value !== "object") return false;
  if (Array.isArray(value)) return false;
  if (value instanceof Date) return false;
  if (value instanceof RegExp) return false;
  if (value instanceof Map) return false;
  if (value instanceof Set) return false;
  if (value instanceof Promise) return false;
  return true;
}

function flattenObjectInternal(
  obj: NestedObject,
  prefix: string,
  result: FlatObject,
  seen: WeakSet<object>
): void {
  if (seen.has(obj)) {
    // Circular reference detected — treat node as a leaf to avoid infinite recursion
    if (prefix !== "") {
      result[prefix] = "[Circular]";
    }
    return;
  }

  seen.add(obj);

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    // Empty object — only emit if it's a nested value, not the root
    if (prefix !== "") {
      result[prefix] = {} as FlatValue;
    }
    seen.delete(obj);
    return;
  }

  for (const key of keys) {
    if (!Object.prototype.hasOwnProperty.call(obj, key)) continue;

    const value = obj[key];
    const newKey = prefix === "" ? key : `${prefix}.${key}`;

    if (isPlainObject(value)) {
      flattenObjectInternal(value, newKey, result, seen);
    } else {
      result[newKey] = value as FlatValue;
    }
  }

  seen.delete(obj);
}

export default function flattenObject(obj: unknown): FlatObject {
  if (!isPlainObject(obj)) {
    throw new TypeError(
      `flattenObject expects a plain object, received: ${
        obj === null ? "null" : Array.isArray(obj) ? "array" : typeof obj
      }`
    );
  }

  const result: FlatObject = {};
  const seen = new WeakSet<object>();
  flattenObjectInternal(obj, "", result, seen);
  return result;
}

type PlainObject = Record<string, unknown>;

function isPlainObject(value: unknown): value is PlainObject {
  return (
    value !== null &&
    typeof value === "object" &&
    !Array.isArray(value) &&
    (Object.getPrototypeOf(value) === Object.prototype ||
      Object.getPrototypeOf(value) === null)
  );
}

function deepMerge(target: unknown, source: unknown): unknown {
  if (isPlainObject(target) && isPlainObject(source)) {
    const result: PlainObject = { ...target };
    for (const key of Object.keys(source)) {
      result[key] = deepMerge(target[key], source[key]);
    }
    return result;
  }

  if (Array.isArray(target) && Array.isArray(source)) {
    return [...target, ...source];
  }

  return source !== undefined ? source : target;
}

export default deepMerge;

type PlainObject = Record<string, unknown>;

const FORBIDDEN_KEYS = new Set(["__proto__", "constructor", "prototype"]);

function isPlainObject(value: unknown): value is PlainObject {
  if (value === null || typeof value !== "object") return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function mergeInternal(
  target: PlainObject,
  source: PlainObject,
  visiting: WeakSet<object>
): PlainObject {
  if (visiting.has(source)) {
    // Circular reference detected — return shallow clone to break the cycle
    // rather than looping infinitely or silently dropping data.
    return Object.assign({}, source);
  }

  visiting.add(source);

  const result: PlainObject = Object.assign({}, target);

  for (const key of Object.keys(source)) {
    // Guard against prototype pollution attacks via crafted keys.
    if (FORBIDDEN_KEYS.has(key)) continue;

    const srcVal = source[key];
    const tgtVal = result[key];

    if (Array.isArray(srcVal) && Array.isArray(tgtVal)) {
      // Concatenate arrays — target first, source appended.
      result[key] = (tgtVal as unknown[]).concat(srcVal);
    } else if (isPlainObject(srcVal) && isPlainObject(tgtVal)) {
      // Both sides are plain objects — recurse.
      result[key] = mergeInternal(tgtVal, srcVal, visiting);
    } else {
      // Primitive, class instance, Date, RegExp, null, mismatched types, etc.
      // Source unconditionally wins.
      result[key] = srcVal;
    }
  }

  visiting.delete(source);

  return result;
}

export default function deepMerge(
  target: unknown,
  source: unknown
): PlainObject {
  if (!isPlainObject(target)) {
    throw new TypeError(
      `deepMerge: 'target' must be a plain object, received ${
        target === null ? "null" : typeof target
      }`
    );
  }
  if (!isPlainObject(source)) {
    throw new TypeError(
      `deepMerge: 'source' must be a plain object, received ${
        source === null ? "null" : typeof source
      }`
    );
  }

  return mergeInternal(target, source, new WeakSet());
}

type NestedObject = Record<string, unknown>;
type FlatObject = Record<string, unknown>;

function isPlainObject(value: unknown): value is object {
  return (
    value !== null &&
    typeof value === "object" &&
    !(value instanceof Date) &&
    !(value instanceof RegExp) &&
    !(value instanceof Error) &&
    !(value instanceof Map) &&
    !(value instanceof Set) &&
    !(value instanceof WeakMap) &&
    !(value instanceof WeakSet) &&
    !(ArrayBuffer.isView(value))
  );
}

function flattenHelper(
  obj: object,
  prefix: string,
  result: FlatObject,
  visited: WeakSet<object>
): void {
  if (visited.has(obj)) {
    // Circular reference — emit a sentinel rather than infinitely recurse
    if (prefix) result[prefix] = "[Circular]";
    return;
  }

  visited.add(obj);

  const entries = Object.entries(obj);

  if (entries.length === 0) {
    // Preserve empty objects/arrays as leaf values so their keys aren't silently dropped
    if (prefix) result[prefix] = obj;
    visited.delete(obj);
    return;
  }

  for (const [key, value] of entries) {
    const newKey = prefix ? `${prefix}.${key}` : key;

    if (isPlainObject(value) || Array.isArray(value)) {
      flattenHelper(value as object, newKey, result, visited);
    } else {
      result[newKey] = value;
    }
  }

  visited.delete(obj);
}

export default function flattenObject(obj: NestedObject): FlatObject {
  if (obj === null || typeof obj !== "object") {
    throw new TypeError(
      `flattenObject expects a non-null object, received: ${obj === null ? "null" : typeof obj}`
    );
  }

  const result: FlatObject = {};
  flattenHelper(obj, "", result, new WeakSet());
  return result;
}

type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<CronField, { min: number; max: number }> = {
  minute: { min: 0, max: 59 },
  hour: { min: 0, max: 23 },
  dayOfMonth: { min: 1, max: 31 },
  month: { min: 1, max: 12 },
  dayOfWeek: { min: 0, max: 7 },
};

function clampAndDedupe(values: number[], min: number, max: number): number[] {
  const valid = values.filter((v) => v >= min && v <= max);
  return [...new Set(valid)].sort((a, b) => a - b);
}

function parseSegment(segment: string, min: number, max: number): number[] {
  // Wildcard
  if (segment === "*") {
    return Array.from({ length: max - min + 1 }, (_, i) => min + i);
  }

  // Step value: */step or range/step
  if (segment.includes("/")) {
    const [rangePart, stepPart] = segment.split("/");
    const step = parseInt(stepPart, 10);

    if (isNaN(step) || step <= 0) {
      throw new Error(`Invalid step value: "${stepPart}"`);
    }

    let start = min;
    let end = max;

    if (rangePart !== "*") {
      if (rangePart.includes("-")) {
        const [rangeStart, rangeEnd] = rangePart.split("-").map(Number);
        start = rangeStart;
        end = rangeEnd;
      } else {
        start = parseInt(rangePart, 10);
      }
    }

    if (isNaN(start) || isNaN(end)) {
      throw new Error(`Invalid range in step expression: "${segment}"`);
    }

    const values: number[] = [];
    for (let i = start; i <= end; i += step) {
      values.push(i);
    }

    return clampAndDedupe(values, min, max);
  }

  // Range: start-end
  if (segment.includes("-")) {
    const [startStr, endStr] = segment.split("-");
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);

    if (isNaN(start) || isNaN(end)) {
      throw new Error(`Invalid range: "${segment}"`);
    }

    if (start > end) {
      throw new Error(`Range start (${start}) must not exceed end (${end})`);
    }

    const values = Array.from({ length: end - start + 1 }, (_, i) => start + i);
    return clampAndDedupe(values, min, max);
  }

  // Comma-separated list
  if (segment.includes(",")) {
    const values = segment.split(",").map((s) => {
      const n = parseInt(s.trim(), 10);
      if (isNaN(n)) {
        throw new Error(`Invalid value in list: "${s}"`);
      }
      return n;
    });
    return clampAndDedupe(values, min, max);
  }

  // Single number
  const value = parseInt(segment, 10);
  if (isNaN(value)) {
    throw new Error(`Invalid cron field value: "${segment}"`);
  }

  return clampAndDedupe([value], min, max);
}

export default function parseCron(expression: string): CronResult {
  if (typeof expression !== "string" || !expression.trim()) {
    throw new Error("Cron expression must be a non-empty string");
  }

  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new Error(
      `Cron expression must have exactly 5 fields, got ${fields.length}: "${expression}"`
    );
  }

  const fieldNames: CronField[] = [
    "minute",
    "hour",
    "dayOfMonth",
    "month",
    "dayOfWeek",
  ];

  const result = {} as CronResult;

  for (let i = 0; i < fieldNames.length; i++) {
    const fieldName = fieldNames[i];
    const { min, max } = FIELD_RANGES[fieldName];
    const segment = fields[i];

    try {
      const values = parseSegment(segment, min, max);

      if (values.length === 0) {
        throw new Error(
          `No valid values for field "${fieldName}" with expression "${segment}" (valid range: ${min}-${max})`
        );
      }

      // Normalize dayOfWeek: treat 7 as 0 (both mean Sunday)
      if (fieldName === "dayOfWeek") {
        const normalized = values.map((v) => (v === 7 ? 0 : v));
        result[fieldName] = [...new Set(normalized)].sort((a, b) => a - b);
      } else {
        result[fieldName] = values;
      }
    } catch (err) {
      throw new Error(
        `Error parsing field "${fieldName}": ${(err as Error).message}`
      );
    }
  }

  return result;
}

export interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

type CronField = keyof CronExpression;

interface FieldRange {
  readonly min: number;
  readonly max: number;
}

const FIELD_ORDER: readonly CronField[] = [
  "minute",
  "hour",
  "dayOfMonth",
  "month",
  "dayOfWeek",
] as const;

// dayOfWeek max is 7 to accept Sunday alias; normalized to 0 after parsing
const FIELD_RANGES: Readonly<Record<CronField, FieldRange>> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 7  },
} as const;

class CronParseError extends Error {
  constructor(message: string) {
    super(message);
    this.name = "CronParseError";
  }
}

function parsePositiveInt(raw: string, context: string): number {
  if (!/^\d+$/.test(raw)) {
    throw new CronParseError(
      `Expected a non-negative integer in ${context}, got "${raw}"`
    );
  }
  const n = Number(raw);
  if (!Number.isFinite(n) || n > Number.MAX_SAFE_INTEGER) {
    throw new CronParseError(`Numeric overflow in ${context}: "${raw}"`);
  }
  return n;
}

function assertInRange(value: number, range: FieldRange, context: string): void {
  if (value < range.min || value > range.max) {
    throw new CronParseError(
      `Value ${value} is out of valid range [${range.min}–${range.max}] in ${context}`
    );
  }
}

function expandSequence(start: number, end: number, step: number): number[] {
  // Guard: step=0 would produce infinite loop; callers must validate first
  const result: number[] = [];
  for (let i = start; i <= end; i += step) {
    result.push(i);
  }
  return result;
}

function parseToken(token: string, range: FieldRange, field: string): number[] {
  if (token === "") {
    throw new CronParseError(`Empty token encountered in field "${field}"`);
  }

  // Pattern: */step
  if (token.startsWith("*/")) {
    const stepStr = token.slice(2);
    if (stepStr === "") {
      throw new CronParseError(`Missing step value after "*/" in field "${field}"`);
    }
    const step = parsePositiveInt(stepStr, `step in "${field}"`);
    if (step === 0) {
      throw new CronParseError(`Step value cannot be zero in field "${field}"`);
    }
    return expandSequence(range.min, range.max, step);
  }

  // Pattern: start-end or start-end/step
  if (token.includes("-")) {
    const slashIndex = token.indexOf("/");
    const rangePart = slashIndex === -1 ? token : token.slice(0, slashIndex);
    const stepPart  = slashIndex === -1 ? null  : token.slice(slashIndex + 1);

    const dashIndex = rangePart.indexOf("-");
    // Guard against multiple dashes (e.g. "1-5-9")
    if (rangePart.indexOf("-", dashIndex + 1) !== -1) {
      throw new CronParseError(
        `Malformed range "${rangePart}" in field "${field}" — multiple dashes`
      );
    }

    const startStr = rangePart.slice(0, dashIndex);
    const endStr   = rangePart.slice(dashIndex + 1);

    if (startStr === "" || endStr === "") {
      throw new CronParseError(
        `Malformed range "${rangePart}" in field "${field}" — missing bound`
      );
    }

    const start = parsePositiveInt(startStr, `range start in "${field}"`);
    const end   = parsePositiveInt(endStr,   `range end in "${field}"`);

    assertInRange(start, range, `range start in "${field}"`);
    assertInRange(end,   range, `range end in "${field}"`);

    if (start > end) {
      throw new CronParseError(
        `Range start (${start}) must be ≤ range end (${end}) in field "${field}"`
      );
    }

    const step = stepPart !== null
      ? parsePositiveInt(stepPart, `step in "${field}"`)
      : 1;

    if (step === 0) {
      throw new CronParseError(`Step value cannot be zero in field "${field}"`);
    }

    return expandSequence(start, end, step);
  }

  // Guard: stray slash that didn't match the above patterns
  if (token.includes("/")) {
    throw new CronParseError(
      `Unexpected "/" in token "${token}" in field "${field}" — use "*/n" or "start-end/n"`
    );
  }

  // Pattern: single integer
  const value = parsePositiveInt(token, `field "${field}"`);
  assertInRange(value, range, `field "${field}"`);
  return [value];
}

function parseField(raw: string, range: FieldRange, field: string): number[] {
  if (raw === "") {
    throw new CronParseError(`Field "${field}" is empty`);
  }

  // Fast path for pure wildcard — avoids going through comma-split
  if (raw === "*") {
    return expandSequence(range.min, range.max, 1);
  }

  const parts = raw.split(",");
  const valueSet = new Set<number>();

  for (const part of parts) {
    if (part === "") {
      throw new CronParseError(
        `Trailing or consecutive comma in field "${field}": "${raw}"`
      );
    }
    const values = parseToken(part, range, field);
    for (const v of values) {
      valueSet.add(v);
    }
  }

  if (valueSet.size === 0) {
    // Shouldn't be reachable, but paranoia is warranted
    throw new CronParseError(`Field "${field}" resolved to an empty value set`);
  }

  return Array.from(valueSet).sort((a, b) => a - b);
}

function normalizeDayOfWeek(values: number[]): number[] {
  // Both 0 and 7 represent Sunday; collapse to 0
  const normalized = new Set(values.map((v) => (v === 7 ? 0 : v)));
  return Array.from(normalized).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronExpression {
  if (typeof expression !== "string") {
    throw new CronParseError(
      `Cron expression must be a string, received ${typeof expression}`
    );
  }

  const trimmed = expression.trim();

  if (trimmed === "") {
    throw new CronParseError("Cron expression must not be empty");
  }

  // Split on any run of whitespace; reject tabs/newlines embedded between fields
  const fields = trimmed.split(/\s+/);

  if (fields.length !== 5) {
    throw new CronParseError(
      `Cron expression must have exactly 5 fields (minute hour dayOfMonth month dayOfWeek), ` +
      `got ${fields.length}: "${expression}"`
    );
  }

  const result = {} as CronExpression;

  for (let i = 0; i < FIELD_ORDER.length; i++) {
    const fieldName  = FIELD_ORDER[i];
    const fieldRange = FIELD_RANGES[fieldName];
    const rawField   = fields[i];

    let values = parseField(rawField, fieldRange, fieldName);

    if (fieldName === "dayOfWeek") {
      values = normalizeDayOfWeek(values);
    }

    result[fieldName] = values;
  }

  return result;
}

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: NestedObject | Primitive | Array<unknown> };
type FlatObject = { [key: string]: Primitive | Array<unknown> };

function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  if (obj === null || typeof obj !== "object" || Array.isArray(obj)) {
    if (prefix) result[prefix] = obj as Primitive | Array<unknown>;
    return result;
  }

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix) result[prefix] = {} as unknown as Primitive;
    return result;
  }

  for (const key of keys) {
    const newKey = prefix ? `${prefix}.${key}` : key;
    const value = obj[key];

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value) &&
      Object.keys(value).length > 0
    ) {
      flattenObject(value as NestedObject, newKey, result);
    } else {
      result[newKey] = value as Primitive | Array<unknown>;
    }
  }

  return result;
}

export default flattenObject;

class LRUCache<T> {
  private capacity: number;
  private map: Map<string, T>;

  constructor(capacity: number) {
    if (capacity <= 0) throw new Error("Capacity must be greater than 0");
    this.capacity = capacity;
    this.map = new Map();
