type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<CronField, { min: number; max: number }> = {
  minute: { min: 0, max: 59 },
  hour: { min: 0, max: 23 },
  dayOfMonth: { min: 1, max: 31 },
  month: { min: 1, max: 12 },
  dayOfWeek: { min: 0, max: 7 },
};

function clamp(value: number, min: number, max: number): number {
  if (value < min || value > max) {
    throw new RangeError(`Value ${value} is out of range [${min}, ${max}]`);
  }
  return value;
}

function range(start: number, end: number): number[] {
  const result: number[] = [];
  for (let i = start; i <= end; i++) result.push(i);
  return result;
}

function parseSegment(segment: string, field: CronField): number[] {
  const { min, max } = FIELD_RANGES[field];

  // Wildcard
  if (segment === "*") {
    return range(min, max);
  }

  // Step: */n or range/n
  if (segment.includes("/")) {
    const [rangePart, stepPart] = segment.split("/");
    const step = parseInt(stepPart, 10);
    if (isNaN(step) || step <= 0) {
      throw new Error(`Invalid step value in segment: "${segment}"`);
    }

    let start: number;
    let end: number;

    if (rangePart === "*") {
      start = min;
      end = max;
    } else if (rangePart.includes("-")) {
      const [lo, hi] = rangePart.split("-").map(Number);
      start = clamp(lo, min, max);
      end = clamp(hi, min, max);
      if (start > end) throw new Error(`Invalid range: ${rangePart}`);
    } else {
      start = clamp(parseInt(rangePart, 10), min, max);
      end = max;
    }

    const result: number[] = [];
    for (let i = start; i <= end; i += step) result.push(i);
    return result;
  }

  // Range: n-m
  if (segment.includes("-")) {
    const parts = segment.split("-");
    if (parts.length !== 2) throw new Error(`Invalid range: "${segment}"`);
    const lo = clamp(parseInt(parts[0], 10), min, max);
    const hi = clamp(parseInt(parts[1], 10), min, max);
    if (lo > hi) throw new Error(`Range start ${lo} > end ${hi}`);
    return range(lo, hi);
  }

  // Single number
  const value = parseInt(segment, 10);
  if (isNaN(value)) throw new Error(`Invalid value: "${segment}"`);
  return [clamp(value, min, max)];
}

function parseField(field: string, fieldName: CronField): number[] {
  const segments = field.split(",");
  const allValues = new Set<number>();

  for (const segment of segments) {
    const values = parseSegment(segment.trim(), fieldName);
    for (const v of values) allValues.add(v);
  }

  // Normalize dayOfWeek: treat 7 as Sunday (0)
  if (fieldName === "dayOfWeek") {
    if (allValues.has(7)) {
      allValues.delete(7);
      allValues.add(0);
    }
  }

  return Array.from(allValues).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronResult {
  if (typeof expression !== "string") {
    throw new TypeError("Cron expression must be a string");
  }

  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5) {
    throw new Error(
      `Expected 5 fields in cron expression, got ${fields.length}`
    );
  }

  const [minuteField, hourField, domField, monthField, dowField] = fields;

  return {
    minute: parseField(minuteField, "minute"),
    hour: parseField(hourField, "hour"),
    dayOfMonth: parseField(domField, "dayOfMonth"),
    month: parseField(monthField, "month"),
    dayOfWeek: parseField(dowField, "dayOfWeek"),
  };
}

type PlainObject = Record<string, unknown>;

function isPlainObject(value: unknown): value is PlainObject {
  if (value === null || typeof value !== "object") return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

const UNSAFE_KEYS = new Set(["__proto__", "constructor", "prototype"]);

function mergeInner<T extends PlainObject, S extends PlainObject>(
  target: T,
  source: S,
  seen: WeakSet<object>
): T & S {
  if (seen.has(source)) {
    // Circular reference in source — return target as-is to avoid infinite recursion
    return { ...target } as T & S;
  }
  seen.add(source);

  const result: PlainObject = { ...target };

  for (const key of Object.keys(source)) {
    if (UNSAFE_KEYS.has(key)) {
      // Prototype pollution guard — skip dangerous keys entirely
      continue;
    }

    const targetVal = result[key];
    const sourceVal = source[key];

    if (Array.isArray(targetVal) && Array.isArray(sourceVal)) {
      result[key] = [...targetVal, ...sourceVal];
    } else if (isPlainObject(targetVal) && isPlainObject(sourceVal)) {
      result[key] = mergeInner(targetVal, sourceVal, seen);
    } else {
      // Primitives, class instances, mixed types: source wins
      result[key] = sourceVal;
    }
  }

  return result as T & S;
}

function deepMerge<T extends PlainObject, S extends PlainObject>(
  target: T,
  source: S
): T & S {
  if (!isPlainObject(target)) {
    throw new TypeError(
      `deepMerge: target must be a plain object, got ${target === null ? "null" : typeof target}`
    );
  }
  if (!isPlainObject(source)) {
    throw new TypeError(
      `deepMerge: source must be a plain object, got ${source === null ? "null" : typeof source}`
    );
  }
  return mergeInner(target, source, new WeakSet());
}

export default deepMerge;

