export interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronResult, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 6],
};

function generateRange(start: number, end: number): number[] {
  const result: number[] = [];
  for (let i = start; i <= end; i++) result.push(i);
  return result;
}

function parseField(field: string, min: number, max: number): number[] {
  const fullRange = generateRange(min, max);

  // Comma-separated list
  if (field.includes(",")) {
    const values = field.split(",").flatMap((part) => parseField(part.trim(), min, max));
    const unique = [...new Set(values)].sort((a, b) => a - b);
    return unique;
  }

  // Step values: */step or start-end/step
  if (field.includes("/")) {
    const [rangePart, stepStr] = field.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step <= 0) throw new Error(`Invalid step value: ${stepStr}`);

    let rangeValues: number[];
    if (rangePart === "*") {
      rangeValues = fullRange;
    } else if (rangePart.includes("-")) {
      const [startStr, endStr] = rangePart.split("-");
      const start = parseInt(startStr, 10);
      const end = parseInt(endStr, 10);
      if (isNaN(start) || isNaN(end)) throw new Error(`Invalid range: ${rangePart}`);
      if (start < min || end > max || start > end)
        throw new Error(`Range ${rangePart} out of bounds [${min}, ${max}]`);
      rangeValues = generateRange(start, end);
    } else {
      const start = parseInt(rangePart, 10);
      if (isNaN(start)) throw new Error(`Invalid step expression: ${field}`);
      if (start < min || start > max)
        throw new Error(`Value ${start} out of bounds [${min}, ${max}]`);
      rangeValues = generateRange(start, max);
    }

    return rangeValues.filter((v) => (v - rangeValues[0]) % step === 0);
  }

  // Wildcard
  if (field === "*") return fullRange;

  // Range: start-end
  if (field.includes("-")) {
    const [startStr, endStr] = field.split("-");
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);
    if (isNaN(start) || isNaN(end)) throw new Error(`Invalid range: ${field}`);
    if (start < min || end > max || start > end)
      throw new Error(`Range ${field} out of bounds [${min}, ${max}]`);
    return generateRange(start, end);
  }

  // Single number
  const value = parseInt(field, 10);
  if (isNaN(value)) throw new Error(`Invalid value: ${field}`);
  if (value < min || value > max)
    throw new Error(`Value ${value} out of bounds [${min}, ${max}]`);
  return [value];
}

export default function parseCron(expression: string): CronResult {
  if (!expression || typeof expression !== "string") {
    throw new Error("Invalid cron expression: must be a non-empty string");
  }

  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5) {
    throw new Error(
      `Invalid cron expression: expected 5 fields, got ${fields.length}`
    );
  }

  const [minuteField, hourField, domField, monthField, dowField] = fields;
  const fieldKeys = Object.keys(FIELD_RANGES) as (keyof CronResult)[];
  const fieldValues = [minuteField, hourField, domField, monthField, dowField];

  const result = {} as CronResult;

  for (let i = 0; i < fieldKeys.length; i++) {
    const key = fieldKeys[i];
    const [min, max] = FIELD_RANGES[key];
    result[key] = parseField(fieldValues[i], min, max);
  }

  return result;
}

interface Node<T> {
  key: string;
  value: T;
  prev: Node<T> | null;
  next: Node<T> | null;
}

export default class LRUCache<T> {
  private readonly capacity: number;
  private readonly map: Map<string, Node<T>>;
  // Sentinel nodes eliminate null-check branches on every operation.
  // head.next = most recently used; tail.prev = least recently used.
  private readonly head: Node<T>;
  private readonly tail: Node<T>;

  constructor(capacity: number) {
    if (!Number.isFinite(capacity) || !Number.isInteger(capacity)) {
      throw new RangeError(
        `LRUCache capacity must be a finite integer, received: ${capacity}`
      );
    }
    if (capacity < 1) {
      throw new RangeError(
        `LRUCache capacity must be at least 1, received: ${capacity}`
      );
    }

    this.capacity = capacity;
    this.map = new Map();

    this.head = { key: "", value: undefined as unknown as T, prev: null, next: null };
    this.tail = { key: "", value: undefined as unknown as T, prev: null, next: null };
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  get(key: string): T | undefined {
    const node = this.map.get(key);
    if (node === undefined) return undefined;
    this.moveToFront(node);
    return node.value;
  }

  set(key: string, value: T): void {
    const existing = this.map.get(key);

    if (existing !== undefined) {
      // Update in-place and promote — no eviction needed.
      existing.value = value;
      this.moveToFront(existing);
      return;
    }

    const node: Node<T> = { key, value, prev: null, next: null };
    this.insertAtFront(node);
    this.map.set(key, node);

    // Evict only after insertion so the map never exceeds capacity + 1 transiently.
    if (this.map.size > this.capacity) {
      // tail.prev is always a real node here: capacity >= 1 and map.size >= 2,
      // so at least one real node sits between the two sentinels.
      const lru = this.tail.prev!;
      this.removeNode(lru);
      this.map.delete(lru.key);
    }
  }

  // ── Private helpers ──────────────────────────────────────────────────────────

  private insertAtFront(node: Node<T>): void {
    const after = this.head.next!; // always non-null; worst case it is tail
    node.prev = this.head;
    node.next = after;
    after.prev = node;
    this.head.next = node;
  }

  private removeNode(node: Node<T>): void {
    // Both prev and next are guaranteed non-null for any real (non-sentinel) node.
    node.prev!.next = node.next;
    node.next!.prev = node.prev;
    node.prev = null;
    node.next = null;
  }

  private moveToFront(node: Node<T>): void {
    this.removeNode(node);
    this.insertAtFront(node);
  }
}

type PlainObject = Record<string, unknown>;

function isPlainObject(value: unknown): value is PlainObject {
  return (
    value !== null &&
    typeof value === "object" &&
    !Array.isArray(value) &&
    (Object.getPrototypeOf(value) === Object.prototype ||
