function cloneValue(value: unknown, seen: WeakMap<object, object>): unknown {
  if (value === null || typeof value !== "object") return value;
  if (seen.has(value)) return seen.get(value);

  if (Array.isArray(value)) {
    const clone: unknown[] = [];
    seen.set(value, clone);
    for (const item of value) {
      clone.push(cloneValue(item, seen));
    }
    return clone;
  }

  if (isPlainObject(value)) {
    const clone: PlainObject = Object.create(Object.getPrototypeOf(value));
    seen.set(value, clone);
    for (const key of Object.keys(value)) {
      clone[key] = cloneValue(value[key], seen);
    }
    return clone;
  }

  // Non-plain objects (Date, RegExp, Map, Set, etc.) are returned by reference — not safe to deep-clone generically
  return value;
}

function mergeValues(
  target: unknown,
  source: unknown,
  seen: WeakMap<object, object>
): unknown {
  // Explicit null/undefined source: keep target (source "has nothing to say")
  if (source === undefined) return cloneValue(target, seen);
  if (source === null) return null;

  // Explicit null/undefined target: clone source wholesale
  if (target === undefined || target === null) return cloneValue(source, seen);

  // Both arrays → concatenate (preserving order: target first, source second)
  if (Array.isArray(target) && Array.isArray(source)) {
    return [
      ...target.map((item) => cloneValue(item, seen)),
      ...source.map((item) => cloneValue(item, seen)),
    ];
  }

  // Both plain objects → merge recursively
  if (isPlainObject(target) && isPlainObject(source)) {
    if (seen.has(source)) return seen.get(source);

    // Start from a shallow copy of target so keys not in source are preserved
    const result: PlainObject = {};
    seen.set(source, result);

    // Copy all target keys first
    for (const key of Object.keys(target)) {
      result[key] = cloneValue(target[key], seen);
    }

    // Merge source keys (may overwrite or recursively merge)
    for (const key of Object.keys(source)) {
      result[key] = mergeValues(target[key], source[key], seen);
    }

    return result;
  }

  // Type mismatch or primitive collision: source wins
  return cloneValue(source, seen);
}

export default function deepMerge<
  T extends PlainObject,
  S extends PlainObject,
>(target: T, source: S): T & S {
  if (!isPlainObject(target)) {
    throw new TypeError(`deepMerge: target must be a plain object, got ${JSON.stringify(target)}`);
  }
  if (!isPlainObject(source)) {
    throw new TypeError(`deepMerge: source must be a plain object, got ${JSON.stringify(source)}`);
  }

  return mergeValues(target, source, new WeakMap()) as T & S;
}

export default class LRUCache<T> {
  private readonly capacity: number;
  private readonly cache: Map<string, T>;

  constructor(capacity: number) {
    if (!Number.isInteger(capacity)) {
      throw new TypeError(`Capacity must be an integer, got: ${capacity}`);
    }
    if (capacity < 0) {
      throw new RangeError(`Capacity must be non-negative, got: ${capacity}`);
    }
    this.capacity = capacity;
    this.cache = new Map<string, T>();
  }

  get(key: string): T | undefined {
    if (key === undefined || key === null) return undefined;
    if (!this.cache.has(key)) return undefined;

    // Re-insert to move to most-recently-used position (Map preserves insertion order)
    const value = this.cache.get(key) as T;
    this.cache.delete(key);
    this.cache.set(key, value);
    return value;
  }

  set(key: string, value: T): void {
    if (key === undefined || key === null) {
      throw new TypeError(`Cache key must not be null or undefined`);
    }
    if (value === undefined) {
      throw new TypeError(`Cache value must not be undefined; use delete() to remove a key`);
    }

    // Zero-capacity cache: storing nothing is the only safe behaviour
    if (this.capacity === 0) return;

    if (this.cache.has(key)) {
      // Delete first so re-insertion moves it to most-recently-used position
      this.cache.delete(key);
    } else if (this.cache.size >= this.capacity) {
      // Evict the least-recently-used entry — the first key in insertion order
      const lruKey = this.cache.keys().next().value;
      if (lruKey !== undefined) {
        this.cache.delete(lruKey);
      }
    }

    this.cache.set(key, value);
  }

  get size(): number {
    return this.cache.size;
  }

  has(key: string): boolean {
    if (key === undefined || key === null) return false;
    return this.cache.has(key);
  }

  delete(key: string): boolean {
    if (key === undefined || key === null) return false;
    return this.cache.delete(key);
  }

  clear(): void {
    this.cache.clear();
  }
}

interface Node<T> {
  key: string;
  value: T;
  prev: Node<T> | null;
  next: Node<T> | null;
}

class LRUCache<T> {
  private readonly capacity: number;
  private readonly map: Map<string, Node<T>>;
  private readonly head: Node<T>; // most recently used sentinel
  private readonly tail: Node<T>; // least recently used sentinel

  constructor(capacity: number) {
    if (!Number.isInteger(capacity) || capacity < 1) {
      throw new RangeError(
        `LRUCache capacity must be a positive integer, got: ${capacity}`
      );
    }

    this.capacity = capacity;
    this.map = new Map();

    // Sentinel nodes eliminate null-edge-case branches throughout
    this.head = { key: "", value: undefined as unknown as T, prev: null, next: null };
    this.tail = { key: "", value: undefined as unknown as T, prev: null, next: null };
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  get(key: string): T | undefined {
    const node = this.map.get(key);
    if (node === undefined) {
      return undefined;
    }
    this.moveToFront(node);
    return node.value;
  }

  set(key: string, value: T): void {
    const existing = this.map.get(key);

    if (existing !== undefined) {
      existing.value = value;
      this.moveToFront(existing);
      return;
    }

    const node: Node<T> = { key, value, prev: null, next: null };
    this.map.set(key, node);
    this.insertAtFront(node);

    if (this.map.size > this.capacity) {
      this.evictLRU();
    }
  }

  private insertAtFront(node: Node<T>): void {
    node.prev = this.head;
    node.next = this.head.next;

    // head.next is always non-null because of the tail sentinel
    this.head.next!.prev = node;
    this.head.next = node;
  }

  private removeNode(node: Node<T>): void {
    // Sentinels guarantee prev and next are never null for real nodes
    node.prev!.next = node.next;
    node.next!.prev = node.prev;
    node.prev = null;
    node.next = null;
  }

  private moveToFront(node: Node<T>): void {
    this.removeNode(node);
    this.insertAtFront(node);
  }

  private evictLRU(): void {
    const lru = this.tail.prev;

    // Guard: only evict if there is a real node between head and tail
    if (lru === null || lru === this.head) {
      return;
    }

    this.removeNode(lru);
    this.map.delete(lru.key);
  }
}

export default LRUCache;

interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldConfig {
  min: number;
  max: number;
}

const FIELD_CONFIGS: FieldConfig[] = [
  { min: 0, max: 59 },  // minute
  { min: 0, max: 23 },  // hour
  { min: 1, max: 31 },  // dayOfMonth
  { min: 1, max: 12 },  // month
  { min: 0, max: 7 },   // dayOfWeek (0 and 7 both = Sunday)
];

function parseNumber(value: string, config: FieldConfig): number {
  const num = parseInt(value, 10);
  if (isNaN(num)) {
    throw new Error(`Invalid numeric value: "${value}"`);
  }
  if (num < config.min || num > config.max) {
    throw new Error(`Value ${num} out of range [${config.min}-${config.max}]`);
  }
  return num;
}

function expandRange(start: number, end: number, config: FieldConfig): number[] {
  if (start < config.min || start > config.max) {
    throw new Error(`Range start ${start} out of range [${config.min}-${config.max}]`);
  }
  if (end < config.min || end > config.max) {
    throw new Error(`Range end ${end} out of range [${config.min}-${config.max}]`);
  }
  if (start > end) {
    throw new Error(`Range start ${start} is greater than end ${end}`);
  }
  const result: number[] = [];
  for (let i = start; i <= end; i++) {
    result.push(i);
  }
  return result;
}

function expandStep(base: string, step: number, config: FieldConfig): number[] {
  if (step <= 0) {
    throw new Error(`Step value must be positive, got ${step}`);
  }
  let start = config.min;
  let end = config.max;

  if (base !== "*") {
    if (base.includes("-")) {
      const [rangeStart, rangeEnd] = base.split("-");
      start = parseNumber(rangeStart, config);
      end = parseNumber(rangeEnd, config);
      if (start > end) {
        throw new Error(`Range start ${start} is greater than end ${end}`);
      }
    } else {
      start = parseNumber(base, config);
    }
  }

  const result: number[] = [];
  for (let i = start; i <= end; i += step) {
    result.push(i);
  }
  return result;
}

function parseField(field: string, config: FieldConfig): number[] {
  // Handle comma-separated list
  if (field.includes(",")) {
    const parts = field.split(",");
    const values = new Set<number>();
    for (const part of parts) {
      const expanded = parseField(part.trim(), config);
      for (const v of expanded) {
        values.add(v);
      }
    }
    return Array.from(values).sort((a, b) => a - b);
  }

  // Handle step value (e.g., */15 or 1-5/2)
  if (field.includes("/")) {
    const slashIndex = field.indexOf("/");
    const base = field.slice(0, slashIndex);
    const stepStr = field.slice(slashIndex + 1);
    const step = parseInt(stepStr, 10);
    if (isNaN(step)) {
      throw new Error(`Invalid step value: "${stepStr}"`);
    }
    return expandStep(base, step, config);
  }

  // Handle wildcard
  if (field === "*") {
    return expandRange(config.min, config.max, config);
  }

  // Handle range (e.g., 1-5)
  if (field.includes("-")) {
    const [startStr, endStr] = field.split("-");
    const start = parseNumber(startStr, config);
    const end = parseNumber(endStr, config);
    return expandRange(start, end, config);
  }

  // Handle single number
  return [parseNumber(field, config)];
}

function normalizeDayOfWeek(values: number[]): number[] {
  // Normalize 7 (Sunday) to 0
  const normalized = new Set(values.map(v => (v === 7 ? 0 : v)));
  return Array.from(normalized).sort((a, b) => a - b);
}

export function parseCron(expression: string): CronFields {
  if (typeof expression !== "string" || expression.trim() === "") {
    throw new Error("Cron expression must be a non-empty string");
  }

  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5) {
    throw new Error(
      `Cron expression must have exactly 5 fields, got ${fields.length}`
    );
  }

  const [minuteField, hourField, domField, monthField, dowField] = fields;

  const minute = parseField(minuteField, FIELD_CONFIGS[0]);
  const hour = parseField(hourField, FIELD_CONFIGS[1]);
  const dayOfMonth = parseField(domField, FIELD_CONFIGS[2]);
  const month = parseField(monthField, FIELD_CONFIGS[3]);
  const dayOfWeek = normalizeDayOfWeek(
    parseField(dowField, FIELD_CONFIGS[4])
  );

  return { minute, hour, dayOfMonth, month, dayOfWeek };
}

export default parseCron;

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | Array<unknown> };
type FlatObject = { [key: string]: Primitive };

function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  if (obj === null || obj === undefined || typeof obj !== "object") {
    result[prefix] = obj as Primitive;
    return result;
  }

  if (Array.isArray(obj)) {
    if (obj.length === 0) {
      result[prefix] = null;
    } else {
      obj.forEach((item, index) => {
        const key = prefix ? `${prefix}.${index}` : `${index}`;
        flattenObject(item as NestedObject, key, result);
      });
    }
    return result;
  }

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix) result[prefix] = null;
    return result;
  }

  for (const key of keys) {
    const sanitizedKey = key.includes(".") ? `[${key}]` : key;
    const newKey = prefix ? `${prefix}.${sanitizedKey}` : sanitizedKey;
    const value = obj[key];

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value) &&
      Object.keys(value).length > 0
    ) {
      flattenObject(value as NestedObject, newKey, result);
    } else if (Array.isArray(value)) {
      flattenObject(value as unknown as NestedObject, newKey, result);
    } else {
      result[newKey] = value as Primitive;
    }
  }

  return result;
}

export default flattenObject;

type Scalar = string | number | boolean | null | undefined | bigint | symbol | Date | RegExp | Function;

function isPlainObject(value: unknown): value is Record<string, unknown> {
  if (value === null || typeof value !== "object") return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function flattenObject(
  obj: Record<string, unknown>,
  prefix = "",
  seen = new WeakSet<object>()
): Record<string, unknown> {
  if (!isPlainObject(obj)) {
    throw new TypeError(`flattenObject: expected a plain object, got ${obj === null ? "null" : typeof obj}`);
  }

  if (seen.has(obj)) {
    throw new Error(`flattenObject: circular reference detected at key "${prefix}"`);
  }

  seen.add(obj);

  const result: Record<string, unknown> = {};

  for (const key of Object.keys(obj)) {
    if (key === "") {
      // Empty-string keys produce ambiguous dot-paths like "a..b"; keep as-is.
    }

    const fullKey = prefix ? `${prefix}.${key}` : key;
    const value = obj[key];

    if (isPlainObject(value)) {
      if (Object.keys(value).length === 0) {
        // Preserve empty objects as leaf values; recursing would lose the key entirely.
        result[fullKey] = value;
      } else {
        const nested = flattenObject(value, fullKey, seen);
        Object.assign(result, nested);
      }
    } else {
      result[fullKey] = value;
    }
  }

  // Remove from seen after processing to allow the same object reference to
  // appear in sibling branches (diamond shapes) without false-positive cycle errors.
  seen.delete(obj);

  return result;
}

export default flattenObject;

type PlainObject = Record<string, unknown>;

const UNSAFE_KEYS = new Set(["__proto__", "constructor", "prototype"]);

function isPlainObject(value: unknown): value is PlainObject {
  if (value === null || typeof value !== "object" || Array.isArray(value)) {
    return false;
  }
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function mergeInternal(
  target: PlainObject,
  source: PlainObject,
  visiting: WeakSet<object>,
): PlainObject {
  if (visiting.has(source)) {
    // Circular reference detected — break cycle by returning shallow copy of target
    return { ...target };
  }

  visiting.add(source);
  const result: PlainObject = { ...target };

  for (const key of Object.keys(source)) {
    // Guard against prototype pollution attacks
    if (UNSAFE_KEYS.has(key)) continue;

    const sourceVal = source[key];
    const targetVal = result[key];

    if (Array.isArray(targetVal) && Array.isArray(sourceVal)) {
      // Concatenate arrays: target first, then source
      result[key] = [...targetVal, ...sourceVal];
    } else if (isPlainObject(targetVal) && isPlainObject(sourceVal)) {
      // Recurse into plain objects
      result[key] = mergeInternal(targetVal, sourceVal, visiting);
    } else {
      // Source overwrites target for all other cases
      // This includes: primitives, Dates, RegExp, Maps, Sets, class instances,
      // mixed types (e.g. target is array but source is object), null, undefined
      result[key] = sourceVal;
    }
  }

  visiting.delete(source);
  return result;
}

export default function deepMerge(target: unknown, source: unknown): unknown {
  // If either argument is not a plain object, treat as a primitive merge: source wins.
  // If source is null/undefined/primitive, return target unchanged (nothing to merge).
  if (source === undefined || source === null) return target;
  if (target === undefined || target === null) return source;

  if (!isPlainObject(target) || !isPlainObject(source)) {
    // One or both sides are non-plain-objects (Date, class instance, primitive, etc.)
    // Source overwrites target per the "otherwise" rule.
    return source;
  }

  return mergeInternal(target, source, new WeakSet());
}

type CronResult = {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
};

const FIELD_RANGES: Record<keyof CronResult, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 7],
};

const range = (from: number, to: number): number[] =>
  Array.from({ length: to - from + 1 }, (_, i) => from + i);

const parseField = (field: string, min: number, max: number): number[] => {
  if (field === "*") return range(min, max);

  if (field.includes(",")) {
    return [...new Set(
      field.split(",").flatMap((part) => parseField(part.trim(), min, max))
    )].sort((a, b) => a - b);
  }

  if (field.includes("/")) {
    const [rangeStr, stepStr] = field.split("/");
    const step = parseInt(stepStr, 10);

    if (isNaN(step) || step <= 0) {
      throw new Error(`Invalid step value: "${stepStr}"`);
    }

    const [from, to] = rangeStr === "*"
      ? [min, max]
      : (() => {
          const parts = rangeStr.split("-");
          if (parts.length === 2) {
            return [parseInt(parts[0], 10), parseInt(parts[1], 10)];
          }
          const start = parseInt(rangeStr, 10);
          return [start, max];
        })();

    if (isNaN(from) || isNaN(to)) {
      throw new Error(`Invalid range in step expression: "${field}"`);
    }

    validateRange(from, to, min, max, field);

    const values: number[] = [];
    for (let i = from; i <= to; i += step) {
      values.push(i);
    }
    return values;
  }

  if (field.includes("-")) {
    const [fromStr, toStr] = field.split("-");
    const from = parseInt(fromStr, 10);
    const to = parseInt(toStr, 10);

    if (isNaN(from) || isNaN(to)) {
      throw new Error(`Invalid range: "${field}"`);
    }

    validateRange(from, to, min, max, field);

    return range(from, to);
  }

  const value = parseInt(field, 10);

  if (isNaN(value)) {
    throw new Error(`Invalid cron field value: "${field}"`);
  }

  if (value < min || value > max) {
    throw new Error(
      `Value ${value} out of valid range [${min}, ${max}] in field "${field}"`
    );
  }

  return [value];
};

const validateRange = (
  from: number,
  to: number,
  min: number,
  max: number,
  field: string
): void => {
  if (from > to) {
    throw new Error(`Invalid range (start > end): "${field}"`);
  }
  if (from < min || to > max) {
    throw new Error(
      `Range "${field}" exceeds valid bounds [${min}, ${max}]`
    );
  }
};

const parseCron = (expression: string): CronResult => {
  if (typeof expression !== "string") {
    throw new Error("Cron expression must be a string");
  }

  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new Error(
      `Expected 5 fields in cron expression, got ${fields.length}: "${expression}"`
    );
  }

  const keys = Object.keys(FIELD_RANGES) as (keyof CronResult)[];

  const result = keys.reduce((acc, key, index) => {
    const [min, max] = FIELD_RANGES[key];
    let values = parseField(fields[index], min, max);

    // Normalize day-of-week: treat 7 as 0 (both represent Sunday)
    if (key === "dayOfWeek") {
      values = [...new Set(values.map((v) => (v === 7 ? 0 : v)))].sort(
        (a, b) => a - b
      );
    }

    return { ...acc, [key]: values };
  }, {} as CronResult);

  return result;
};

export default parseCron;

const FIELD_RANGES = {
  minute: { min: 0, max: 59 },
  hour: { min: 0, max: 23 },
  dayOfMonth: { min: 1, max: 31 },
  month: { min: 1, max: 12 },
  dayOfWeek: { min: 0, max: 7 },
} as const;

type FieldName = keyof typeof FIELD_RANGES;

interface ParsedCron {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

function rangeArray(start: number, end: number, step = 1): number[] {
  const result: number[] = [];
  for (let i = start; i <= end; i += step) {
    result.push(i);
  }
  return result;
}

function validateValue(value: number, field: FieldName): number {
  const { min, max } = FIELD_RANGES[field];
  if (!Number.isInteger(value) || value < min || value > max) {
    throw new RangeError(
      `Value ${value} is out of range [${min}, ${max}] for field "${field}"`
    );
  }
  return value;
}

function parseSegment(segment: string, field: FieldName): number[] {
  const { min, max } = FIELD_RANGES[field];

  // Wildcard: *
  if (segment === "*") {
    return rangeArray(min, max);
  }

  // Step: */n or range/n
  if (segment.includes("/")) {
    const [rangePart, stepPart] = segment.split("/");
    const step = parseInt(stepPart, 10);

    if (isNaN(step) || step < 1) {
      throw new SyntaxError(`Invalid step value "${stepPart}" in field "${field}"`);
    }

    let start = min;
    let end = max;

    if (rangePart !== "*") {
      if (rangePart.includes("-")) {
        const [rangeStart, rangeEnd] = rangePart.split("-").map(Number);
        if (isNaN(rangeStart) || isNaN(rangeEnd)) {
          throw new SyntaxError(`Invalid range "${rangePart}" in field "${field}"`);
        }
        start = validateValue(rangeStart, field);
        end = validateValue(rangeEnd, field);
        if (start > end) {
          throw new RangeError(`Range start ${start} > end ${end} in field "${field}"`);
        }
      } else {
        start = validateValue(parseInt(rangePart, 10), field);
        end = max;
      }
    }

    return rangeArray(start, end, step);
  }

  // Range: n-m
  if (segment.includes("-")) {
    const parts = segment.split("-");
    if (parts.length !== 2) {
      throw new SyntaxError(`Invalid range "${segment}" in field "${field}"`);
    }
    const start = validateValue(parseInt(parts[0], 10), field);
    const end = validateValue(parseInt(parts[1], 10), field);
    if (start > end) {
      throw new RangeError(`Range start ${start} > end ${end} in field "${field}"`);
    }
    return rangeArray(start, end);
  }

  // Single number
  const num = parseInt(segment, 10);
  if (isNaN(num)) {
    throw new SyntaxError(`Invalid value "${segment}" in field "${field}"`);
  }
  return [validateValue(num, field)];
}

function parseField(expression: string, field: FieldName): number[] {
  const segments = expression.split(",");
  const values = new Set<number>();

  for (const segment of segments) {
    const trimmed = segment.trim();
    if (!trimmed) {
      throw new SyntaxError(`Empty segment in field "${field}"`);
    }
    for (const val of parseSegment(trimmed, field)) {
      // Normalize dayOfWeek: treat 7 as 0 (both mean Sunday)
      if (field === "dayOfWeek" && val === 7) {
        values.add(0);
      } else {
        values.add(val);
      }
    }
  }

  return Array.from(values).sort((a, b) => a - b);
}

export default function parseCron(expression: string): ParsedCron {
  if (typeof expression !== "string" || !expression.trim()) {
    throw new SyntaxError("Cron expression must be a non-empty string");
  }

  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5) {
    throw new SyntaxError(
      `Expected 5 fields, got ${fields.length}. Format: "minute hour dayOfMonth month dayOfWeek"`
    );
  }

  const [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr] = fields;

  return {
    minute: parseField(minuteExpr, "minute"),
    hour: parseField(hourExpr, "hour"),
    dayOfMonth: parseField(domExpr, "dayOfMonth"),
    month: parseField(monthExpr, "month"),
    dayOfWeek: parseField(dowExpr, "dayOfWeek"),
  };
}

export default class LRUCache<T> {
  private readonly capacity: number;
  private readonly cache: Map<string, T>;

  constructor(capacity: number) {
    if (capacity < 1) throw new RangeError("Capacity must be at least 1");
    this.capacity = capacity;
    this.cache = new Map();
  }

  get(key: string): T | undefined {
    if (!this.cache.has(key)) return undefined;
    const value = this.cache.get(key) as T;
    this.cache.delete(key);
    this.cache.set(key, value);
    return value;
  }

  set(key: string, value: T): void {
    if (this.cache.has(key)) {
      this.cache.delete(key);
    } else if (this.cache.size >= this.capacity) {
      this.cache.delete(this.cache.keys().next().value as string);
    }
    this.cache.set(key, value);
  }
}

interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronFields, { min: number; max: number }> = {
  minute: { min: 0, max: 59 },
  hour: { min: 0, max: 23 },
  dayOfMonth: { min: 1, max: 31 },
  month: { min: 1, max: 12 },
  dayOfWeek: { min: 0, max: 6 },
};

const clamp = (value: number, min: number, max: number): number =>
  Math.max(min, Math.min(max, value));

const range = (start: number, end: number): number[] =>
  Array.from({ length: end - start + 1 }, (_, i) => start + i);

const parseSegment = (
  segment: string,
  min: number,
  max: number
): number[] => {
  const fullRange = range(min, max);

  if (segment === "*") {
    return fullRange;
  }

  if (segment.startsWith("*/")) {
    const step = parseInt(segment.slice(2), 10);
    if (isNaN(step) || step <= 0) {
      throw new Error(`Invalid step value: ${segment}`);
    }
    return fullRange.filter((v) => (v - min) % step === 0);
  }

  if (segment.includes("/")) {
    const [rangePart, stepPart] = segment.split("/");
    const step = parseInt(stepPart, 10);
    if (isNaN(step) || step <= 0) {
      throw new Error(`Invalid step value in: ${segment}`);
    }

    let start = min;
    let end = max;

    if (rangePart !== "*") {
      if (rangePart.includes("-")) {
        const [s, e] = rangePart.split("-").map((n) => parseInt(n, 10));
        if (isNaN(s) || isNaN(e)) throw new Error(`Invalid range in: ${segment}`);
        start = clamp(s, min, max);
        end = clamp(e, min, max);
      } else {
        start = clamp(parseInt(rangePart, 10), min, max);
      }
    }

    return range(start, end).filter((v) => (v - start) % step === 0);
  }

  if (segment.includes(",")) {
    const values = segment.split(",").flatMap((part) => parseSegment(part.trim(), min, max));
    return [...new Set(values)].sort((a, b) => a - b);
  }

  if (segment.includes("-")) {
    const [startStr, endStr] = segment.split("-");
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);
    if (isNaN(start) || isNaN(end)) {
      throw new Error(`Invalid range: ${segment}`);
    }
    if (start > end) {
      throw new Error(`Range start must be <= end: ${segment}`);
    }
    const s = clamp(start, min, max);
    const e = clamp(end, min, max);
    return range(s, e);
  }

  const value = parseInt(segment, 10);
  if (isNaN(value)) {
    throw new Error(`Invalid cron field value: ${segment}`);
  }
  if (value < min || value > max) {
    throw new Error(`Value ${value} out of range [${min}, ${max}]`);
  }
  return [value];
};

const parseCron = (expression: string): CronFields => {
  const parts = expression.trim().split(/\s+/);

  if (parts.length !== 5) {
    throw new Error(
      `Invalid cron expression: expected 5 fields, got ${parts.length}`
    );
  }

  const fieldNames = Object.keys(FIELD_RANGES) as (keyof CronFields)[];

  const result = fieldNames.reduce((acc, field, index) => {
    const { min, max } = FIELD_RANGES[field];
    acc[field] = parseSegment(parts[index], min, max);
    return acc;
  }, {} as CronFields);

  return result;
};

export default parseCron;

export default class LRUCache<T> {
  private readonly capacity: number;
  private readonly cache: Map<string, T>;

  constructor(capacity: number) {
    if (!Number.isInteger(capacity) || capacity < 0) {
      throw new RangeError(
        `LRUCache capacity must be a non-negative integer, got: ${capacity}`
      );
    }
    this.capacity = capacity;
    this.cache = new Map<string, T>();
  }

  get(key: string): T | undefined {
    if (!this.cache.has(key)) {
      return undefined;
    }
    // Guaranteed defined because has() returned true
    const value = this.cache.get(key) as T;
    // Promote to most-recently-used by deleting and re-inserting
    this.cache.delete(key);
    this.cache.set(key, value);
    return value;
  }

  set(key: string, value: T): void {
    // Zero-capacity cache stores nothing — all sets are silent no-ops
    if (this.capacity === 0) {
      return;
    }

    if (this.cache.has(key)) {
      // Remove first so the re-insert lands at the MRU tail
      this.cache.delete(key);
    } else if (this.cache.size >= this.capacity) {
      // Map iteration order is insertion order; first key is LRU
      const lruKey = this.cache.keys().next().value;
      // Guard against a theoretically empty iterator (shouldn't happen, but
      // evicting an undefined key would silently corrupt the Map otherwise)
      if (lruKey !== undefined) {
        this.cache.delete(lruKey);
      }
    }

    this.cache.set(key, value);
  }
}

type FlatValue = string | number | boolean | null | undefined | symbol | bigint | object;

function isPlainObject(value: unknown): value is Record<string, unknown> {
  if (value === null || typeof value !== "object") return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function flattenObjectInternal(
  obj: Record<string, unknown>,
  prefix: string,
  result: Record<string, FlatValue>,
  seen: WeakSet<object>,
): void {
  if (seen.has(obj)) {
    throw new TypeError(
      `Circular reference detected${prefix ? ` at key: "${prefix}"` : ""}`,
    );
  }

  seen.add(obj);

  const keys = Object.keys(obj);

  for (const key of keys) {
    const value = obj[key];
    const fullKey = prefix.length > 0 ? `${prefix}.${key}` : key;

    if (Array.isArray(value)) {
      if (value.length === 0) {
        result[fullKey] = value;
      } else {
        flattenObjectInternal(
          value as unknown as Record<string, unknown>,
          fullKey,
          result,
          seen,
        );
      }
    } else if (isPlainObject(value)) {
      if (Object.keys(value).length === 0) {
        result[fullKey] = value;
      } else {
        flattenObjectInternal(value, fullKey, result, seen);
      }
    } else {
      result[fullKey] = value as FlatValue;
    }
  }

  seen.delete(obj);
}

export default function flattenObject(
  obj: unknown,
): Record<string, FlatValue> {
  if (obj === null || obj === undefined) {
    throw new TypeError(
      `flattenObject expects a plain object, received: ${obj}`,
    );
  }

  if (!isPlainObject(obj)) {
    throw new TypeError(
      `flattenObject expects a plain object, received: ${Object.prototype.toString.call(obj)}`,
    );
  }

  const result: Record<string, FlatValue> = {};
  flattenObjectInternal(obj, "", result, new WeakSet());
  return result;
}

type FlatValue = string | number | boolean | null | undefined | bigint | symbol | unknown[];

interface FlattenedObject {
  [key: string]: FlatValue;
}

function isPlainObject(value: unknown): value is Record<string, unknown> {
  if (value === null || typeof value !== "object") return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function flattenInternal(
  obj: Record<string, unknown>,
  prefix: string,
  result: FlattenedObject,
  ancestors: Set<object>
): void {
  if (ancestors.has(obj)) {
    throw new TypeError(
      `Circular reference detected${prefix ? ` at key "${prefix.slice(0, -1)}"` : ""}`
    );
  }

  ancestors.add(obj);

  for (const key of Object.keys(obj)) {
    const value = obj[key];
    const fullKey = prefix ? `${prefix}.${key}` : key;

    if (isPlainObject(value)) {
      const nested = value as Record<string, unknown>;
      if (Object.keys(nested).length === 0) {
        // Preserve empty objects as leaf values so callers know the key existed
        (result as Record<string, unknown>)[fullKey] = {};
      } else {
        flattenInternal(nested, `${fullKey}.`, result, ancestors);
      }
    } else {
      (result as Record<string, unknown>)[fullKey] = value;
    }
  }

  // Backtrack so sibling branches sharing the same object reference are not
  // incorrectly flagged as circular references
  ancestors.delete(obj);
}

export default function flattenObject(
  obj: Record<string, unknown>
): FlattenedObject {
  if (!isPlainObject(obj)) {
    throw new TypeError(
      `flattenObject expects a plain object, received: ${
        obj === null ? "null" : typeof obj
      }`
    );
  }

  const result: FlattenedObject = {};
  flattenInternal(obj, "", result, new Set<object>());
  return result;
}

export interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

type FieldName = keyof CronFields;

const FIELD_RANGES: Record<FieldName, { min: number; max: number }> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
};

const FIELD_ORDER: FieldName[] = [
  "minute",
  "hour",
  "dayOfMonth",
  "month",
  "dayOfWeek",
];

function parseInteger(raw: string, fieldName: FieldName): number {
  if (!/^\d+$/.test(raw)) {
    throw new Error(
      `Field "${fieldName}": "${raw}" is not a valid non-negative integer.`
    );
  }
  const n = parseInt(raw, 10);
  if (!Number.isFinite(n)) {
    throw new Error(
      `Field "${fieldName}": "${raw}" overflows a safe integer.`
    );
  }
  return n;
}

function assertInRange(
  value: number,
  min: number,
  max: number,
  fieldName: FieldName,
  context: string
): void {
  if (value < min || value > max) {
    throw new RangeError(
      `Field "${fieldName}" (context: "${context}"): value ${value} is outside ` +
        `the valid range [${min}, ${max}].`
    );
  }
}

function buildRange(start: number, end: number, step: number): number[] {
  const values: number[] = [];
  for (let i = start; i <= end; i += step) {
    values.push(i);
  }
  return values;
}

/**
 * Parses a single atom — anything that does NOT contain a comma.
 * Handles: *, number, range (a-b), step (x/n), range+step (a-b/n).
 */
function parseAtom(atom: string, fieldName: FieldName): number[] {
  const { min, max } = FIELD_RANGES[fieldName];

  // ── step expression ──────────────────────────────────────────────────────
  if (atom.includes("/")) {
    const slashIdx = atom.indexOf("/");
    const secondSlash = atom.indexOf("/", slashIdx + 1);
    if (secondSlash !== -1) {
      throw new SyntaxError(
        `Field "${fieldName}": "${atom}" contains more than one "/".`
      );
    }

    const rangePart = atom.slice(0, slashIdx);
    const stepPart  = atom.slice(slashIdx + 1);

    if (stepPart === "") {
      throw new SyntaxError(
        `Field "${fieldName}": "${atom}" has an empty step value.`
      );
    }

    const step = parseInteger(stepPart, fieldName);
    if (step === 0) {
      throw new RangeError(
        `Field "${fieldName}": step value of 0 is not allowed.`
      );
    }

    let rangeMin: number;
    let rangeMax: number;

    if (rangePart === "*") {
      rangeMin = min;
      rangeMax = max;
    } else if (rangePart.includes("-")) {
      [rangeMin, rangeMax] = parseDashRange(rangePart, fieldName);
    } else {
      rangeMin = parseInteger(rangePart, fieldName);
      assertInRange(rangeMin, min, max, fieldName, atom);
      rangeMax = max;
    }

    return buildRange(rangeMin, rangeMax, step);
  }

  // ── wildcard ─────────────────────────────────────────────────────────────
  if (atom === "*") {
    return buildRange(min, max, 1);
  }

  // ── range ────────────────────────────────────────────────────────────────
  if (atom.includes("-")) {
    const [rangeMin, rangeMax] = parseDashRange(atom, fieldName);
    return buildRange(rangeMin, rangeMax, 1);
  }

  // ── single value ─────────────────────────────────────────────────────────
  const value = parseInteger(atom, fieldName);
  assertInRange(value, min, max, fieldName, atom);
  return [value];
}

function parseDashRange(
  raw: string,
  fieldName: FieldName
): [number, number] {
  const { min, max } = FIELD_RANGES[fieldName];
  const parts = raw.split("-");

  if (parts.length !== 2 || parts[0] === "" || parts[1] === "") {
    throw new SyntaxError(
      `Field "${fieldName}": "${raw}" is not a valid range (expected "a-b").`
    );
  }

  const start = parseInteger(parts[0], fieldName);
  const end   = parseInteger(parts[1], fieldName);

  assertInRange(start, min, max, fieldName, raw);
  assertInRange(end,   min, max, fieldName, raw);

  if (start > end) {
    throw new RangeError(
      `Field "${fieldName}": range start (${start}) must not exceed ` +
        `range end (${end}) in "${raw}".`
    );
  }

  return [start, end];
}

function parseField(expression: string, fieldName: FieldName): number[] {
  if (expression === "" || expression.trim() !== expression) {
    throw new SyntaxError(
      `Field "${fieldName}": expression must be non-empty and have no ` +
        `leading/trailing whitespace (got "${expression}").`
    );
  }

  const atoms = expression.split(",");

  if (atoms.some((a) => a === "")) {
    throw new SyntaxError(
      `Field "${fieldName}": "${expression}" contains an empty atom ` +
        `(stray comma?).`
    );
  }

  const seen = new Set<number>();
  for (const atom of atoms) {
    for (const v of parseAtom(atom, fieldName)) {
      seen.add(v);
    }
  }

  return Array.from(seen).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronFields {
  if (expression === null || expression === undefined) {
    throw new TypeError("parseCron: expression must be a string, got null/undefined.");
  }
  if (typeof expression !== "string") {
    throw new TypeError(
      `parseCron: expression must be a string, got ${typeof expression}.`
    );
  }

  const trimmed = expression.trim();
  if (trimmed === "") {
    throw new SyntaxError("parseCron: expression must not be empty.");
  }

  // Collapse internal whitespace to a single space so callers don't have to
  // worry about tabs or multiple spaces between fields.
  const tokens = trimmed.split(/\s+/);

  if (tokens.length !== 5) {
    throw new SyntaxError(
      `parseCron: expected exactly 5 whitespace-separated fields, ` +
        `got ${tokens.length} in "${expression}".`
    );
  }

  const result = {} as CronFields;

  for (let i = 0; i < FIELD_ORDER.length; i++) {
    const fieldName = FIELD_ORDER[i];
    result[fieldName] = parseField(tokens[i], fieldName);
  }

  return result;
}

type PlainObject = Record<string, unknown>;

function isPlainObject(value: unknown): value is PlainObject {
  if (value === null || typeof value !== "object") return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function mergeInternal(
  target: PlainObject,
  source: PlainObject,
  seen: WeakMap<PlainObject, PlainObject>
): PlainObject {
  if (seen.has(source)) {
    return seen.get(source)!;
  }

  const result: PlainObject = { ...target };
  seen.set(source, result);

  for (const key of Object.keys(source)) {
    const sourceVal = source[key];

    // Never overwrite with undefined — treat as "not provided"
    if (sourceVal === undefined) continue;

    const targetVal = result[key];

    if (Array.isArray(sourceVal) && Array.isArray(targetVal)) {
      result[key] = [...targetVal, ...sourceVal];
    } else if (isPlainObject(sourceVal) && isPlainObject(targetVal)) {
      result[key] = mergeInternal(targetVal, sourceVal, seen);
    } else {
      result[key] = sourceVal;
    }
  }

  return result;
}

export default function deepMerge<
  T extends PlainObject,
  S extends PlainObject
>(target: T, source: S): T & S {
  if (!isPlainObject(target) && !isPlainObject(source)) {
    return {} as T & S;
  }
  if (!isPlainObject(target)) {
    return { ...source } as T & S;
  }
  if (!isPlainObject(source)) {
    return { ...target } as T & S;
  }

  return mergeInternal(target, source, new WeakMap()) as T & S;
}

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | Array<unknown> };
type FlatObject = { [key: string]: Primitive | Array<unknown> };

function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  if (obj === null || typeof obj !== "object" || Array.isArray(obj)) {
    if (prefix) result[prefix] = obj as Primitive | Array<unknown>;
    return result;
  }

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix) result[prefix] = {} as unknown as Primitive;
    return result;
  }

  for (const key of keys) {
    const value = obj[key];
    const newKey = prefix ? `${prefix}.${key}` : key;

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value) &&
      Object.keys(value).length > 0
    ) {
      flattenObject(value as NestedObject, newKey, result);
    } else {
      result[newKey] = value as Primitive | Array<unknown>;
    }
  }

  return result;
}

export default flattenObject;

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | Array<unknown> };
type FlatObject = { [key: string]: Primitive };

function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  if (obj === null || obj === undefined || typeof obj !== "object") {
    if (prefix) result[prefix] = obj as Primitive;
    return result;
  }

  if (Array.isArray(obj)) {
    if (prefix) result[prefix] = JSON.stringify(obj);
    return result;
  }

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix) result[prefix] = "{}";
    return result;
  }

  for (const key of keys) {
    const newKey = prefix ? `${prefix}.${key}` : key;
    const value = obj[key];

    if (
      value !== null &&
      value !== undefined &&
      typeof value === "object" &&
      !Array.isArray(value)
    ) {
      flattenObject(value as NestedObject, newKey, result);
    } else if (Array.isArray(value)) {
      result[newKey] = JSON.stringify(value);
    } else {
      result[newKey] = value as Primitive;
    }
  }

  return result;
}

export default flattenObject;

class LRUCache<T> {
  private capacity: number;
  private map: Map<string, T>;

  constructor(capacity: number) {
    if (capacity <= 0) throw new RangeError("Capacity must be a positive integer");
    this.capacity = Math.floor(capacity);
    this.map = new Map();
  }

  get(key: string): T | undefined {
    if (!this.map.has(key)) return undefined;
    const value = this.map.get(key) as T;
    this.map.delete(key);
    this.map.set(key, value);
    return value;
  }

  set(key: string, value: T): void {
    if (this.map.has(key)) {
      this.map.delete(key);
    } else if (this.map.size >= this.capacity) {
      const lruKey = this.map.keys().next().value as string;
      this.map.delete(lruKey);
    }
    this.map.set(key, value);
  }
}

export default LRUCache;

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

type FieldConfig = {
  min: number;
  max: number;
};

const FIELD_CONFIGS: Record<keyof CronResult, FieldConfig> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
};

function parseField(field: string, config: FieldConfig): number[] {
  const { min, max } = config;

  const allValues = (): number[] =>
    Array.from({ length: max - min + 1 }, (_, i) => i + min);

  const clampAndValidate = (value: number, fieldMin: number, fieldMax: number): number => {
    if (value < fieldMin || value > fieldMax) {
      throw new RangeError(
        `Value ${value} is out of range [${fieldMin}, ${fieldMax}]`
      );
    }
    return value;
  };

  const parseNumber = (str: string, fieldMin: number, fieldMax: number): number => {
    const num = parseInt(str, 10);
    if (isNaN(num) || str.trim() !== String(num)) {
      throw new TypeError(`Invalid numeric value: "${str}"`);
    }
    return clampAndValidate(num, fieldMin, fieldMax);
  };

  const parseSegment = (segment: string): number[] => {
    // Step: */n or range/n
    if (segment.includes("/")) {
      const [rangePart, stepPart] = segment.split("/");
      const step = parseInt(stepPart, 10);
      if (isNaN(step) || step <= 0) {
        throw new TypeError(`Invalid step value: "${stepPart}"`);
      }

      let start = min;
      let end = max;

      if (rangePart !== "*") {
        if (rangePart.includes("-")) {
          const [startStr, endStr] = rangePart.split("-");
          start = parseNumber(startStr, min, max);
          end = parseNumber(endStr, min, max);
          if (start > end) {
            throw new RangeError(`Invalid range: ${start}-${end}`);
          }
        } else {
          start = parseNumber(rangePart, min, max);
          end = max;
        }
      }

      const values: number[] = [];
      for (let i = start; i <= end; i += step) {
        values.push(i);
      }
      return values;
    }

    // Wildcard
    if (segment === "*") {
      return allValues();
    }

    // Range: n-m
    if (segment.includes("-")) {
      const [startStr, endStr] = segment.split("-");
      const start = parseNumber(startStr, min, max);
      const end = parseNumber(endStr, min, max);
      if (start > end) {
        throw new RangeError(`Invalid range: ${start}-${end}`);
      }
      return Array.from({ length: end - start + 1 }, (_, i) => i + start);
    }

    // Single number
    return [parseNumber(segment, min, max)];
  };

  // Comma-separated list
  const segments = field.split(",");
  const valueSet = new Set<number>();
  for (const segment of segments) {
    for (const value of parseSegment(segment.trim())) {
      valueSet.add(value);
    }
  }

  return Array.from(valueSet).sort((a, b) => a - b);
}

function parseCron(expression: string): CronResult {
  if (typeof expression !== "string") {
    throw new TypeError("Cron expression must be a string");
  }

  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5) {
    throw new Error(
      `Invalid cron expression: expected 5 fields, got ${fields.length}`
    );
  }

  const [minuteField, hourField, dayOfMonthField, monthField, dayOfWeekField] = fields;
  const keys = Object.keys(FIELD_CONFIGS) as (keyof CronResult)[];
  const rawFields = [minuteField, hourField, dayOfMonthField, monthField, dayOfWeekField];

  const result = {} as CronResult;
  for (let i = 0; i < keys.length; i++) {
    const key = keys[i];
    result[key] = parseField(rawFields[i], FIELD_CONFIGS[key]);
  }

  return result;
}

export default parseCron;

type PlainObject = Record<string, unknown>;

function isPlainObject(value: unknown): value is PlainObject {
  return (
    value !== null &&
    typeof value === "object" &&
    !Array.isArray(value) &&
    (Object.getPrototypeOf(value) === Object.prototype ||
      Object.getPrototypeOf(value) === null)
  );
}

function deepMerge(target: unknown, source: unknown): unknown {
  if (isPlainObject(target) && isPlainObject(source)) {
    const result: PlainObject = { ...target };
    for (const key of Object.keys(source)) {
      result[key] = deepMerge(target[key], source[key]);
    }
    return result;
  }

  if (Array.isArray(target) && Array.isArray(source)) {
    return [...target, ...source];
  }

  return source !== undefined ? source : target;
}

export default deepMerge;

