export interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_NAMES = ["minute", "hour", "dayOfMonth", "month", "dayOfWeek"] as const;
type FieldName = (typeof FIELD_NAMES)[number];

const FIELD_RANGES: Record<FieldName, { min: number; max: number }> = {
  minute:     { min: 0, max: 59 },
  hour:       { min: 0, max: 23 },
  dayOfMonth: { min: 1, max: 31 },
  month:      { min: 1, max: 12 },
  dayOfWeek:  { min: 0, max: 7  },
};

function buildRange(start: number, end: number): number[] {
  const result: number[] = [];
  for (let i = start; i <= end; i++) result.push(i);
  return result;
}

function parseStrictInt(s: string, context: string): number {
  const trimmed = s.trim();
  if (!/^\d+$/.test(trimmed)) {
    throw new Error(`Expected a non-negative integer, got "${s}" in "${context}"`);
  }
  return parseInt(trimmed, 10);
}

function assertInBounds(value: number, min: number, max: number, context: string): void {
  if (value < min || value > max) {
    throw new RangeError(`Value ${value} is outside valid range [${min}, ${max}] in "${context}"`);
  }
}

function parseFieldPart(token: string, min: number, max: number): number[] {
  const trimmed = token.trim();
  if (trimmed === "") {
    throw new Error("Encountered empty field part (possible stray comma or whitespace)");
  }

  // Step expression: */N  or  A-B/N  or  A/N
  if (trimmed.includes("/")) {
    const slashParts = trimmed.split("/");
    if (slashParts.length !== 2) {
      throw new Error(`Expected exactly one '/' in step expression, got "${trimmed}"`);
    }

    const [rangeStr, stepStr] = slashParts;
    const step = parseStrictInt(stepStr, trimmed);
    if (step === 0) {
      throw new Error(`Step value must be greater than zero in "${trimmed}"`);
    }

    let start: number;
    let end: number;

    if (rangeStr === "*") {
      start = min;
      end = max;
    } else if (rangeStr.includes("-")) {
      const dashParts = rangeStr.split("-");
      if (dashParts.length !== 2) {
        throw new Error(`Invalid range "${rangeStr}" in step expression "${trimmed}"`);
      }
      start = parseStrictInt(dashParts[0], trimmed);
      end   = parseStrictInt(dashParts[1], trimmed);
    } else {
      start = parseStrictInt(rangeStr, trimmed);
      end   = max;
    }

    assertInBounds(start, min, max, trimmed);
    assertInBounds(end,   min, max, trimmed);
    if (start > end) {
      throw new RangeError(`Range start ${start} exceeds end ${end} in "${trimmed}"`);
    }

    const values: number[] = [];
    for (let i = start; i <= end; i += step) values.push(i);
    return values;
  }

  // Wildcard
  if (trimmed === "*") {
    return buildRange(min, max);
  }

  // Range: A-B
  if (trimmed.includes("-")) {
    const dashParts = trimmed.split("-");
    if (dashParts.length !== 2) {
      throw new Error(`Invalid range expression "${trimmed}" — expected exactly one '-'`);
    }
    const start = parseStrictInt(dashParts[0], trimmed);
    const end   = parseStrictInt(dashParts[1], trimmed);
    assertInBounds(start, min, max, trimmed);
    assertInBounds(end,   min, max, trimmed);
    if (start > end) {
      throw new RangeError(`Range start ${start} exceeds end ${end} in "${trimmed}"`);
    }
    return buildRange(start, end);
  }

  // Single value
  const value = parseStrictInt(trimmed, trimmed);
  assertInBounds(value, min, max, trimmed);
  return [value];
}

function parseField(token: string, fieldName: FieldName): number[] {
  const trimmed = token.trim();
  if (trimmed === "") {
    throw new Error(`Field "${fieldName}" is empty`);
  }

  const { min, max } = FIELD_RANGES[fieldName];

  const accumulator = new Set<number>();
  const parts = trimmed.split(",");

  for (const part of parts) {
    if (part.trim() === "") {
      throw new Error(
        `Empty item in comma-separated list for field "${fieldName}": "${token}"`
      );
    }
    for (const v of parseFieldPart(part, min, max)) {
      accumulator.add(v);
    }
  }

  return Array.from(accumulator).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronExpression {
  if (typeof expression !== "string") {
    throw new TypeError(`Cron expression must be a string, got ${typeof expression}`);
  }

  const trimmed = expression.trim();
  if (trimmed === "") {
    throw new Error("Cron expression must not be empty");
  }

  const fields = trimmed.split(/\s+/);
  if (fields.length !== 5) {
    throw new Error(
      `Cron expression requires exactly 5 space-separated fields, got ${fields.length}: "${expression}"`
    );
  }

  const [minuteToken, hourToken, domToken, monthToken, dowToken] = fields;

  return {
    minute:     parseField(minuteToken, "minute"),
    hour:       parseField(hourToken,   "hour"),
    dayOfMonth: parseField(domToken,    "dayOfMonth"),
    month:      parseField(monthToken,  "month"),
    dayOfWeek:  parseField(dowToken,    "dayOfWeek"),
  };
}

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | Array<unknown> };
type FlatObject = { [key: string]: Primitive };

function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  if (obj === null || typeof obj !== "object" || Array.isArray(obj)) {
    if (prefix) result[prefix] = obj as Primitive;
    return result;
  }

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix) result[prefix] = {} as unknown as Primitive;
    return result;
  }

  for (const key of keys) {
    const value = obj[key];
    const newKey = prefix ? `${prefix}.${key}` : key;

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value)
    ) {
      flattenObject(value as NestedObject, newKey, result);
    } else {
      result[newKey] = value as Primitive;
    }
  }

  return result;
}

export default flattenObject;

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | Array<unknown> };
type FlatObject = { [key: string]: Primitive };

function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  if (obj === null || obj === undefined || typeof obj !== "object") {
    if (prefix) result[prefix] = obj as Primitive;
    return result;
  }

  if (Array.isArray(obj)) {
    if (obj.length === 0) {
      if (prefix) result[prefix] = null;
      return result;
    }
    obj.forEach((value, index) => {
      flattenObject(
        value as NestedObject,
        prefix ? `${prefix}.${index}` : `${index}`,
        result
      );
    });
    return result;
  }

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix) result[prefix] = null;
    return result;
  }

  for (const key of keys) {
    const newKey = prefix ? `${prefix}.${key}` : key;
    const value = obj[key];

    if (
      value !== null &&
      value !== undefined &&
      typeof value === "object" &&
      !Array.isArray(value)
    ) {
      flattenObject(value as NestedObject, newKey, result);
    } else if (Array.isArray(value)) {
      flattenObject(value as unknown as NestedObject, newKey, result);
    } else {
      result[newKey] = value as Primitive;
    }
  }

  return result;
}

export default flattenObject;

interface Node<T> {
  key: string;
  value: T;
  prev: Node<T> | null;
  next: Node<T> | null;
}

class LRUCache<T> {
  private readonly capacity: number;
  private readonly map: Map<string, Node<T>>;
  // Sentinel nodes: head.next = LRU end, tail.prev = MRU end
  private readonly head: Node<T>;
  private readonly tail: Node<T>;

  constructor(capacity: number) {
    if (!Number.isInteger(capacity) || capacity < 1) {
      throw new RangeError(
        `LRUCache capacity must be a positive integer, received: ${capacity}`
      );
    }
    this.capacity = capacity;
    this.map = new Map();
    // Dummy sentinels with placeholder values — never exposed externally
    this.head = { key: "__head__", value: undefined as unknown as T, prev: null, next: null };
    this.tail = { key: "__tail__", value: undefined as unknown as T, prev: null, next: null };
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  get(key: string): T | undefined {
    const node = this.map.get(key);
    if (node === undefined) {
      return undefined;
    }
    this.promoteToMRU(node);
    return node.value;
  }

  set(key: string, value: T): void {
    const existing = this.map.get(key);
    if (existing !== undefined) {
      existing.value = value;
      this.promoteToMRU(existing);
      return;
    }

    const node: Node<T> = { key, value, prev: null, next: null };
    this.map.set(key, node);
    this.insertBeforeTail(node);

    if (this.map.size > this.capacity) {
      this.evictLRU();
    }
  }

  get size(): number {
    return this.map.size;
  }

  private promoteToMRU(node: Node<T>): void {
    this.unlink(node);
    this.insertBeforeTail(node);
  }

  private unlink(node: Node<T>): void {
    // Sentinels guarantee prev/next are never null for real nodes
    const prev = node.prev!;
    const next = node.next!;
    prev.next = next;
    next.prev = prev;
    node.prev = null;
    node.next = null;
  }

  private insertBeforeTail(node: Node<T>): void {
    const prev = this.tail.prev!;
    prev.next = node;
    node.prev = prev;
    node.next = this.tail;
    this.tail.prev = node;
  }

  private evictLRU(): void {
    const lru = this.head.next!;
    // Guard against evicting the tail sentinel (empty cache — should not
    // happen given capacity >= 1, but defend anyway)
    if (lru === this.tail) {
      return;
    }
    this.unlink(lru);
    this.map.delete(lru.key);
  }
}

export default LRUCache;

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronResult, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 6],
};

function rangeArray(start: number, end: number): number[] {
  const result: number[] = [];
  for (let i = start; i <= end; i++) result.push(i);
  return result;
}

function parseField(field: string, min: number, max: number): number[] {
  // Comma-separated list
  if (field.includes(",")) {
    const values = field.split(",").flatMap((part) => parseField(part.trim(), min, max));
    return [...new Set(values)].sort((a, b) => a - b);
  }

  // Wildcard
  if (field === "*") {
    return rangeArray(min, max);
  }

  // Step value: */n or range/n
  if (field.includes("/")) {
    const [rangePart, stepStr] = field.split("/");
    const step = parseInt(stepStr, 10);

    if (isNaN(step) || step <= 0) {
      throw new Error(`Invalid step value: ${stepStr}`);
    }

    let rangeMin = min;
    let rangeMax = max;

    if (rangePart !== "*") {
      if (rangePart.includes("-")) {
        const [startStr, endStr] = rangePart.split("-");
        rangeMin = parseInt(startStr, 10);
        rangeMax = parseInt(endStr, 10);
      } else {
        rangeMin = parseInt(rangePart, 10);
      }
    }

    if (isNaN(rangeMin) || isNaN(rangeMax)) {
      throw new Error(`Invalid range in step expression: ${field}`);
    }

    validateRange(rangeMin, rangeMax, min, max);

    const result: number[] = [];
    for (let i = rangeMin; i <= rangeMax; i += step) result.push(i);
    return result;
  }

  // Range: n-m
  if (field.includes("-")) {
    const [startStr, endStr] = field.split("-");
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);

    if (isNaN(start) || isNaN(end)) {
      throw new Error(`Invalid range: ${field}`);
    }

    if (start > end) {
      throw new Error(`Range start (${start}) must be <= end (${end})`);
    }

    validateRange(start, end, min, max);
    return rangeArray(start, end);
  }

  // Single number
  const value = parseInt(field, 10);

  if (isNaN(value)) {
    throw new Error(`Invalid cron field value: ${field}`);
  }

  if (value < min || value > max) {
    throw new Error(`Value ${value} is out of range [${min}, ${max}]`);
  }

  return [value];
}

function validateRange(start: number, end: number, min: number, max: number): void {
  if (start < min || start > max) {
    throw new Error(`Value ${start} is out of range [${min}, ${max}]`);
  }
  if (end < min || end > max) {
    throw new Error(`Value ${end} is out of range [${min}, ${max}]`);
  }
}

function parseCron(expression: string): CronResult {
  if (typeof expression !== "string" || !expression.trim()) {
    throw new Error("Cron expression must be a non-empty string");
  }

  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new Error(
      `Cron expression must have exactly 5 fields, got ${fields.length}`
    );
  }

  const [minuteStr, hourStr, dayOfMonthStr, monthStr, dayOfWeekStr] = fields;
  const keys = Object.keys(FIELD_RANGES) as (keyof CronResult)[];

  const result = {} as CronResult;

  const fieldStrings = [minuteStr, hourStr, dayOfMonthStr, monthStr, dayOfWeekStr];

  for (let i = 0; i < keys.length; i++) {
    const key = keys[i];
    const [min, max] = FIELD_RANGES[key];
    try {
      result[key] = parseField(fieldStrings[i], min, max);
    } catch (err) {
      throw new Error(
        `Error parsing field "${key}" with value "${fieldStrings[i]}": ${(err as Error).message}`
      );
    }
  }

  return result;
}

export default parseCron;

class LRUCache<T> {
  private capacity: number;
  private map: Map<string, T>;

  constructor(capacity: number) {
    if (capacity <= 0) throw new RangeError("Capacity must be a positive integer");
    this.capacity = Math.floor(capacity);
    this.map = new Map();
  }

  get(key: string): T | undefined {
    if (!this.map.has(key)) return undefined;
    const value = this.map.get(key) as T;
    this.map.delete(key);
    this.map.set(key, value);
    return value;
  }

  set(key: string, value: T): void {
    if (this.map.has(key)) {
      this.map.delete(key);
    } else if (this.map.size >= this.capacity) {
      const lruKey = this.map.keys().next().value as string;
      this.map.delete(lruKey);
    }
    this.map.set(key, value);
  }
}

export default LRUCache;

export interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

type FieldName = keyof CronFields;

interface FieldMeta {
  name: FieldName;
  min: number;
  max: number;
}

const FIELD_META: FieldMeta[] = [
  { name: "minute",     min: 0,  max: 59 },
  { name: "hour",       min: 0,  max: 23 },
  { name: "dayOfMonth", min: 1,  max: 31 },
  { name: "month",      min: 1,  max: 12 },
  { name: "dayOfWeek",  min: 0,  max: 6  },
];

function isUnsignedInt(s: string): boolean {
  return s.length > 0 && /^\d+$/.test(s);
}

function parseField(
  expr: string,
  fieldName: string,
  min: number,
  max: number
): number[] {
  if (expr === "" || expr !== expr.trim()) {
    throw new Error(
      `Invalid cron field for "${fieldName}": must be non-empty and untrimmed, got "${expr}"`
    );
  }

  const segments = expr.split(",");

  if (segments.some((s) => s === "")) {
    throw new Error(
      `Invalid cron field for "${fieldName}": empty segment caused by consecutive or trailing commas in "${expr}"`
    );
  }

  const values = new Set<number>();

  for (const segment of segments) {
    const slashParts = segment.split("/");

    if (slashParts.length > 2) {
      throw new Error(
        `Invalid cron segment "${segment}" for "${fieldName}": only one "/" is allowed per segment`
      );
    }

    const rangeExpr = slashParts[0];
    const stepStr = slashParts[1];

    let step: number | undefined;

    if (stepStr !== undefined) {
      if (!isUnsignedInt(stepStr)) {
        throw new Error(
          `Invalid step value "${stepStr}" in "${segment}" for "${fieldName}": must be a positive integer`
        );
      }
      step = parseInt(stepStr, 10);
      if (step === 0) {
        throw new Error(
          `Invalid step value 0 in "${segment}" for "${fieldName}": step must be >= 1`
        );
      }
    }

    let rangeMin: number;
    let rangeMax: number;

    if (rangeExpr === "*") {
      rangeMin = min;
      rangeMax = max;
    } else if (rangeExpr.includes("-")) {
      const dashIdx = rangeExpr.indexOf("-");
      const startStr = rangeExpr.slice(0, dashIdx);
      const endStr = rangeExpr.slice(dashIdx + 1);

      if (!isUnsignedInt(startStr) || !isUnsignedInt(endStr)) {
        throw new Error(
          `Invalid range "${rangeExpr}" in "${segment}" for "${fieldName}": both bounds must be non-negative integers`
        );
      }

      rangeMin = parseInt(startStr, 10);
      rangeMax = parseInt(endStr, 10);

      if (rangeMin < min || rangeMin > max) {
        throw new Error(
          `Range start ${rangeMin} is out of bounds [${min}, ${max}] for "${fieldName}"`
        );
      }
      if (rangeMax < min || rangeMax > max) {
        throw new Error(
          `Range end ${rangeMax} is out of bounds [${min}, ${max}] for "${fieldName}"`
        );
      }
      if (rangeMin > rangeMax) {
        throw new Error(
          `Range start ${rangeMin} must not exceed range end ${rangeMax} for "${fieldName}"`
        );
      }
    } else {
      if (!isUnsignedInt(rangeExpr)) {
        throw new Error(
          `Invalid value "${rangeExpr}" in "${segment}" for "${fieldName}": must be a non-negative integer, "*", or a range`
        );
      }

      const val = parseInt(rangeExpr, 10);

      if (val < min || val > max) {
        throw new Error(
          `Value ${val} is out of bounds [${min}, ${max}] for "${fieldName}"`
        );
      }

      rangeMin = val;
      // "N/step" means: starting at N, every `step` up to field max (standard cron semantics)
      rangeMax = step !== undefined ? max : val;
    }

    const stepVal = step ?? 1;
    for (let v = rangeMin; v <= rangeMax; v += stepVal) {
      values.add(v);
    }
  }

  return Array.from(values).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronFields {
  if (typeof expression !== "string") {
    throw new TypeError(
      `Cron expression must be a string, got ${typeof expression}`
    );
  }

  const trimmed = expression.trim();

  if (trimmed === "") {
    throw new Error("Cron expression must not be empty or whitespace-only");
  }

  const rawFields = trimmed.split(/\s+/);

  if (rawFields.length !== 5) {
    throw new Error(
      `Cron expression must have exactly 5 whitespace-separated fields, got ${rawFields.length} in "${expression}"`
    );
  }

  const result = {} as CronFields;

  for (let i = 0; i < FIELD_META.length; i++) {
    const { name, min, max } = FIELD_META[i];
    result[name] = parseField(rawFields[i], name, min, max);
  }

  return result;
}

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | Array<unknown> };
type FlatObject = { [key: string]: Primitive | Array<unknown> };

function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  if (obj === null || obj === undefined || typeof obj !== "object" || Array.isArray(obj)) {
    if (prefix) result[prefix] = obj as Primitive | Array<unknown>;
    return result;
  }

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix) result[prefix] = {} as unknown as Primitive;
    return result;
  }

  for (const key of keys) {
    const value = obj[key];
    const newKey = prefix ? `${prefix}.${key}` : key;

    if (
      value !== null &&
      value !== undefined &&
      typeof value === "object" &&
      !Array.isArray(value)
    ) {
      flattenObject(value as NestedObject, newKey, result);
    } else {
      result[newKey] = value as Primitive | Array<unknown>;
    }
  }

  return result;
}

export default flattenObject;

class LRUCache<T> {
  private capacity: number;
  private map: Map<string, T>;

  constructor(capacity: number) {
    if (capacity < 1) throw new RangeError("Capacity must be at least 1");
    this.capacity = capacity;
    this.map = new Map();
  }

  get(key: string): T | undefined {
    if (!this.map.has(key)) return undefined;
    const value = this.map.get(key)!;
    this.map.delete(key);
    this.map.set(key, value);
    return value;
  }

  set(key: string, value: T): void {
    if (this.map.has(key)) {
      this.map.delete(key);
    } else if (this.map.size >= this.capacity) {
      this.map.delete(this.map.keys().next().value!);
    }
    this.map.set(key, value);
  }
}

export default LRUCache;

type PlainObject = Record<string, unknown>;

function isPlainObject(value: unknown): value is PlainObject {
  if (value === null || typeof value !== "object") return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function deepMerge(target: unknown, source: unknown): unknown {
  if (Array.isArray(target) && Array.isArray(source)) {
    return [...target, ...source];
  }

  if (isPlainObject(target) && isPlainObject(source)) {
    const result: PlainObject = { ...target };

    for (const key of Object.keys(source)) {
      result[key] = key in target
        ? deepMerge(target[key], source[key])
        : source[key];
    }

    return result;
  }

  return source === undefined ? target : source;
}

export default deepMerge;

type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<CronField, { min: number; max: number }> = {
  minute: { min: 0, max: 59 },
  hour: { min: 0, max: 23 },
  dayOfMonth: { min: 1, max: 31 },
  month: { min: 1, max: 12 },
  dayOfWeek: { min: 0, max: 7 },
};

function clampAndValidate(value: number, field: CronField): number {
  const { min, max } = FIELD_RANGES[field];
  if (value < min || value > max) {
    throw new RangeError(
      `Value ${value} is out of range [${min}, ${max}] for field "${field}"`
    );
  }
  return value;
}

function unique(arr: number[]): number[] {
  return [...new Set(arr)].sort((a, b) => a - b);
}

function parseSegment(segment: string, field: CronField): number[] {
  const { min, max } = FIELD_RANGES[field];

  // Wildcard: *
  if (segment === "*") {
    return Array.from({ length: max - min + 1 }, (_, i) => i + min);
  }

  // Step with wildcard: */n
  const stepWildcardMatch = segment.match(/^\*\/(\d+)$/);
  if (stepWildcardMatch) {
    const step = parseInt(stepWildcardMatch[1], 10);
    if (step <= 0) {
      throw new RangeError(`Step value must be positive, got ${step} for field "${field}"`);
    }
    const values: number[] = [];
    for (let i = min; i <= max; i += step) {
      values.push(i);
    }
    return values;
  }

  // Step with range: n-m/s
  const stepRangeMatch = segment.match(/^(\d+)-(\d+)\/(\d+)$/);
  if (stepRangeMatch) {
    const rangeMin = parseInt(stepRangeMatch[1], 10);
    const rangeMax = parseInt(stepRangeMatch[2], 10);
    const step = parseInt(stepRangeMatch[3], 10);
    clampAndValidate(rangeMin, field);
    clampAndValidate(rangeMax, field);
    if (rangeMin > rangeMax) {
      throw new RangeError(
        `Range start ${rangeMin} must be <= range end ${rangeMax} for field "${field}"`
      );
    }
    if (step <= 0) {
      throw new RangeError(`Step value must be positive, got ${step} for field "${field}"`);
    }
    const values: number[] = [];
    for (let i = rangeMin; i <= rangeMax; i += step) {
      values.push(i);
    }
    return values;
  }

  // Range: n-m
  const rangeMatch = segment.match(/^(\d+)-(\d+)$/);
  if (rangeMatch) {
    const rangeMin = parseInt(rangeMatch[1], 10);
    const rangeMax = parseInt(rangeMatch[2], 10);
    clampAndValidate(rangeMin, field);
    clampAndValidate(rangeMax, field);
    if (rangeMin > rangeMax) {
      throw new RangeError(
        `Range start ${rangeMin} must be <= range end ${rangeMax} for field "${field}"`
      );
    }
    return Array.from({ length: rangeMax - rangeMin + 1 }, (_, i) => i + rangeMin);
  }

  // Plain number
  const numMatch = segment.match(/^(\d+)$/);
  if (numMatch) {
    const value = parseInt(numMatch[1], 10);
    clampAndValidate(value, field);
    return [value];
  }

  throw new SyntaxError(`Invalid cron segment "${segment}" for field "${field}"`);
}

function parseField(expression: string, field: CronField): number[] {
  const parts = expression.split(",");
  const values = parts.flatMap((part) => parseSegment(part.trim(), field));
  const result = unique(values);

  // Normalize dayOfWeek: treat 7 as 0 (both represent Sunday)
  if (field === "dayOfWeek") {
    return unique(result.map((v) => (v === 7 ? 0 : v)));
  }

  return result;
}

export default function parseCron(expression: string): CronResult {
  if (typeof expression !== "string") {
    throw new TypeError("Cron expression must be a string");
  }

  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new SyntaxError(
      `Cron expression must have exactly 5 fields, got ${fields.length}: "${expression}"`
    );
  }

  const [minuteExpr, hourExpr, dayOfMonthExpr, monthExpr, dayOfWeekExpr] = fields;

  return {
    minute: parseField(minuteExpr, "minute"),
    hour: parseField(hourExpr, "hour"),
    dayOfMonth: parseField(dayOfMonthExpr, "dayOfMonth"),
    month: parseField(monthExpr, "month"),
    dayOfWeek: parseField(dayOfWeekExpr, "dayOfWeek"),
  };
}

class LRUCache<T> {
  private capacity: number;
  private map: Map<string, T>;

  constructor(capacity: number) {
    if (capacity < 1) throw new RangeError("Capacity must be at least 1");
    this.capacity = capacity;
    this.map = new Map();
  }

  get(key: string): T | undefined {
    if (!this.map.has(key)) return undefined;
    const value = this.map.get(key) as T;
    this.map.delete(key);
    this.map.set(key, value);
    return value;
  }

  set(key: string, value: T): void {
    if (this.map.has(key)) {
      this.map.delete(key);
    } else if (this.map.size >= this.capacity) {
      this.map.delete(this.map.keys().next().value as string);
    }
    this.map.set(key, value);
  }
}

export default LRUCache;

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | Array<unknown> };
type FlatObject = { [key: string]: Primitive };

function flattenObject(
  obj: NestedObject | Array<unknown>,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  if (obj === null || obj === undefined) return result;

  for (const [key, value] of Object.entries(obj)) {
    const flatKey = prefix ? `${prefix}.${key}` : key;

    if (value === null || value === undefined) {
      result[flatKey] = value as Primitive;
    } else if (Array.isArray(value)) {
      flattenObject(value as Array<unknown>, flatKey, result);
    } else if (typeof value === "object") {
      flattenObject(value as NestedObject, flatKey, result);
    } else {
      result[flatKey] = value as Primitive;
    }
  }

  return result;
}

export default flattenObject;

type PlainObject = Record<string, unknown>;

function isPlainObject(value: unknown): value is PlainObject {
  return (
    value !== null &&
    typeof value === "object" &&
    !Array.isArray(value) &&
    (Object.getPrototypeOf(value) === Object.prototype ||
      Object.getPrototypeOf(value) === null)
  );
}

export function deepMerge<T extends PlainObject, S extends PlainObject>(
  target: T,
  source: S
): T & S {
  if (!isPlainObject(target) || !isPlainObject(source)) {
    return (isPlainObject(source) ? source : target) as T & S;
  }

  const result: PlainObject = { ...target };

  for (const key of Object.keys(source)) {
    const targetVal = result[key];
    const sourceVal = source[key];

    if (Array.isArray(targetVal) && Array.isArray(sourceVal)) {
      result[key] = [...targetVal, ...sourceVal];
    } else if (isPlainObject(targetVal) && isPlainObject(sourceVal)) {
      result[key] = deepMerge(targetVal, sourceVal);
    } else {
      result[key] = sourceVal;
    }
  }

  return result as T & S;
}

export default deepMerge;

interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronFields, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 6],
};

function range(start: number, end: number): number[] {
  const result: number[] = [];
  for (let i = start; i <= end; i++) result.push(i);
  return result;
}

function parseField(field: string, min: number, max: number): number[] {
  const allValues = range(min, max);

  // Wildcard
  if (field === "*") return allValues;

  // Step value: */n or range/n
  if (field.includes("/")) {
    const [rangepart, stepStr] = field.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step <= 0) throw new Error(`Invalid step value: "${stepStr}"`);

    let base: number[];
    if (rangepart === "*") {
      base = allValues;
    } else if (rangepart.includes("-")) {
      const [startStr, endStr] = rangepart.split("-");
      const start = parseInt(startStr, 10);
      const end = parseInt(endStr, 10);
      if (isNaN(start) || isNaN(end)) throw new Error(`Invalid range in step: "${rangepart}"`);
      if (start < min || end > max || start > end)
        throw new Error(`Range "${rangepart}" out of bounds [${min}-${max}]`);
      base = range(start, end);
    } else {
      const start = parseInt(rangepart, 10);
      if (isNaN(start)) throw new Error(`Invalid step base: "${rangepart}"`);
      if (start < min || start > max)
        throw new Error(`Value ${start} out of bounds [${min}-${max}]`);
      base = range(start, max);
    }

    return base.filter((v) => (v - base[0]) % step === 0);
  }

  // Comma-separated list
  if (field.includes(",")) {
    const parts = field.split(",");
    const values = new Set<number>();
    for (const part of parts) {
      for (const v of parseField(part.trim(), min, max)) values.add(v);
    }
    return Array.from(values).sort((a, b) => a - b);
  }

  // Range: n-m
  if (field.includes("-")) {
    const [startStr, endStr] = field.split("-");
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);
    if (isNaN(start) || isNaN(end)) throw new Error(`Invalid range: "${field}"`);
    if (start < min || end > max || start > end)
      throw new Error(`Range "${field}" out of bounds [${min}-${max}]`);
    return range(start, end);
  }

  // Single number
  const value = parseInt(field, 10);
  if (isNaN(value)) throw new Error(`Invalid field value: "${field}"`);
  if (value < min || value > max)
    throw new Error(`Value ${value} out of bounds [${min}-${max}]`);
  return [value];
}

export default function parseCron(expression: string): CronFields {
  if (typeof expression !== "string" || !expression.trim()) {
    throw new Error("Cron expression must be a non-empty string");
  }

  const parts = expression.trim().split(/\s+/);
  if (parts.length !== 5) {
    throw new Error(`Expected 5 fields, got ${parts.length}: "${expression}"`);
  }

  const fieldNames = Object.keys(FIELD_RANGES) as (keyof CronFields)[];

  const result = {} as CronFields;
  for (let i = 0; i < fieldNames.length; i++) {
    const name = fieldNames[i];
    const [min, max] = FIELD_RANGES[name];
    try {
      result[name] = parseField(parts[i], min, max);
    } catch (err) {
      throw new Error(
        `Invalid cron field "${name}" (position ${i + 1}) with value "${parts[i]}": ${(err as Error).message}`
      );
    }
  }

  return result;
}

type PlainObject = Record<string, unknown>;

function isPlainObject(value: unknown): value is PlainObject {
  return (
    value !== null &&
    typeof value === "object" &&
    !Array.isArray(value) &&
    (Object.getPrototypeOf(value) === Object.prototype ||
      Object.getPrototypeOf(value) === null)
  );
}

export default function deepMerge<T extends PlainObject, S extends PlainObject>(
  target: T,
  source: S
): T & S {
  if (!isPlainObject(target) || !isPlainObject(source)) {
    return (isPlainObject(source) ? source : target) as T & S;
  }

  const result: PlainObject = { ...target };

  for (const key of Object.keys(source)) {
    const targetVal = result[key];
    const sourceVal = source[key];

    if (Array.isArray(targetVal) && Array.isArray(sourceVal)) {
      result[key] = [...targetVal, ...sourceVal];
    } else if (isPlainObject(targetVal) && isPlainObject(sourceVal)) {
      result[key] = deepMerge(targetVal, sourceVal);
    } else {
      result[key] = sourceVal;
    }
  }

  return result as T & S;
}

interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronFields, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 6],
};

function range(start: number, end: number): number[] {
  const result: number[] = [];
  for (let i = start; i <= end; i++) result.push(i);
  return result;
}

function parseField(field: string, min: number, max: number): number[] {
  const fullRange = range(min, max);

  if (field === "*") return fullRange;

  if (field.startsWith("*/")) {
    const step = parseInt(field.slice(2), 10);
    if (isNaN(step) || step <= 0) throw new Error(`Invalid step value: ${field}`);
    return fullRange.filter((v) => (v - min) % step === 0);
  }

  if (field.includes(",")) {
    const values = field.split(",").flatMap((part) => parseField(part.trim(), min, max));
    return [...new Set(values)].sort((a, b) => a - b);
  }

  if (field.includes("/")) {
    const [rangePart, stepPart] = field.split("/");
    const step = parseInt(stepPart, 10);
    if (isNaN(step) || step <= 0) throw new Error(`Invalid step value: ${field}`);

    let base: number[];
    if (rangePart === "*") {
      base = fullRange;
    } else if (rangePart.includes("-")) {
      const [startStr, endStr] = rangePart.split("-");
      const start = parseInt(startStr, 10);
      const end = parseInt(endStr, 10);
      if (isNaN(start) || isNaN(end)) throw new Error(`Invalid range: ${rangePart}`);
      if (start < min || end > max || start > end)
        throw new Error(`Range out of bounds: ${rangePart} (valid: ${min}-${max})`);
      base = range(start, end);
    } else {
      const start = parseInt(rangePart, 10);
      if (isNaN(start)) throw new Error(`Invalid value: ${rangePart}`);
      if (start < min || start > max)
        throw new Error(`Value out of bounds: ${start} (valid: ${min}-${max})`);
      base = range(start, max);
    }

    return base.filter((v) => (v - base[0]) % step === 0);
  }

  if (field.includes("-")) {
    const [startStr, endStr] = field.split("-");
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);
    if (isNaN(start) || isNaN(end)) throw new Error(`Invalid range: ${field}`);
    if (start < min || end > max || start > end)
      throw new Error(`Range out of bounds: ${field} (valid: ${min}-${max})`);
    return range(start, end);
  }

  const value = parseInt(field, 10);
  if (isNaN(value)) throw new Error(`Invalid field value: ${field}`);
  if (value < min || value > max)
    throw new Error(`Value out of bounds: ${value} (valid: ${min}-${max})`);
  return [value];
}

export default function parseCron(expression: string): CronFields {
  if (typeof expression !== "string") throw new Error("Cron expression must be a string");

  const parts = expression.trim().split(/\s+/);
  if (parts.length !== 5)
    throw new Error(`Invalid cron expression: expected 5 fields, got ${parts.length}`);

  const [minutePart, hourPart, domPart, monthPart, dowPart] = parts;
  const fieldNames = Object.keys(FIELD_RANGES) as (keyof CronFields)[];
  const fieldValues = [minutePart, hourPart, domPart, monthPart, dowPart];

  const result = {} as CronFields;

  for (let i = 0; i < fieldNames.length; i++) {
    const name = fieldNames[i];
    const [min, max] = FIELD_RANGES[name];
    try {
      result[name] = parseField(fieldValues[i], min, max);
    } catch (err) {
      throw new Error(
        `Invalid value for field "${name}": ${fieldValues[i]} — ${(err as Error).message}`
      );
    }
  }

  return result;
}

class LRUCache<T> {
  private capacity: number;
  private map: Map<string, T>;

  constructor(capacity: number) {
    if (capacity < 1) throw new RangeError("Capacity must be at least 1");
    this.capacity = capacity;
    this.map = new Map();
  }

  get(key: string): T | undefined {
    if (!this.map.has(key)) return undefined;
    const value = this.map.get(key) as T;
    this.map.delete(key);
    this.map.set(key, value);
    return value;
  }

  set(key: string, value: T): void {
    if (this.map.has(key)) {
      this.map.delete(key);
    } else if (this.map.size >= this.capacity) {
      this.map.delete(this.map.keys().next().value as string);
    }
    this.map.set(key, value);
