export default LRUCache;

export interface CronSchedule {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldConfig {
  readonly name: keyof CronSchedule;
  readonly min: number;
  readonly max: number;
}

const FIELD_CONFIGS: readonly FieldConfig[] = [
  { name: "minute", min: 0, max: 59 },
  { name: "hour", min: 0, max: 23 },
  { name: "dayOfMonth", min: 1, max: 31 },
  { name: "month", min: 1, max: 12 },
  { name: "dayOfWeek", min: 0, max: 6 },
];

const INTEGER_PATTERN = /^\d+$/;

function assertInteger(raw: string, fieldName: string): number {
  if (!INTEGER_PATTERN.test(raw)) {
    throw new SyntaxError(
      `Expected integer in field "${fieldName}", got "${raw}"`
    );
  }
  return parseInt(raw, 10);
}

function assertInRange(
  value: number,
  min: number,
  max: number,
  fieldName: string
): void {
  if (value < min || value > max) {
    throw new RangeError(
      `Value ${value} out of valid range [${min}, ${max}] for field "${fieldName}"`
    );
  }
}

function expandRange(
  start: number,
  end: number,
  step: number,
  fieldName: string
): number[] {
  if (start > end) {
    throw new RangeError(
      `Range start (${start}) must not exceed end (${end}) in field "${fieldName}"`
    );
  }
  if (step <= 0) {
    throw new RangeError(
      `Step must be a positive integer in field "${fieldName}", got ${step}`
    );
  }

  const values: number[] = [];
  for (let i = start; i <= end; i += step) {
    values.push(i);
  }
  return values;
}

function parseSegment(
  segment: string,
  min: number,
  max: number,
  fieldName: string
): number[] {
  if (segment === "") {
    throw new SyntaxError(`Empty segment in field "${fieldName}"`);
  }

  const slashIndex = segment.indexOf("/");

  if (slashIndex !== -1) {
    const rangePart = segment.slice(0, slashIndex);
    const stepPart = segment.slice(slashIndex + 1);

    if (stepPart === "") {
      throw new SyntaxError(
        `Missing step value after "/" in field "${fieldName}"`
      );
    }

    const step = assertInteger(stepPart, fieldName);
    if (step <= 0) {
      throw new RangeError(
        `Step must be a positive integer in field "${fieldName}", got ${step}`
      );
    }

    if (rangePart === "*") {
      return expandRange(min, max, step, fieldName);
    }

    const dashIndex = rangePart.indexOf("-");
    if (dashIndex !== -1) {
      const startRaw = rangePart.slice(0, dashIndex);
      const endRaw = rangePart.slice(dashIndex + 1);
      if (startRaw === "" || endRaw === "") {
        throw new SyntaxError(
          `Malformed range "${rangePart}" in field "${fieldName}"`
        );
      }
      const start = assertInteger(startRaw, fieldName);
      const end = assertInteger(endRaw, fieldName);
      assertInRange(start, min, max, fieldName);
      assertInRange(end, min, max, fieldName);
      return expandRange(start, end, step, fieldName);
    }

    const base = assertInteger(rangePart, fieldName);
    assertInRange(base, min, max, fieldName);
    return expandRange(base, max, step, fieldName);
  }

  if (segment === "*") {
    return expandRange(min, max, 1, fieldName);
  }

  const dashIndex = segment.indexOf("-");
  if (dashIndex !== -1) {
    if (dashIndex === 0 || dashIndex === segment.length - 1) {
      throw new SyntaxError(
        `Malformed range "${segment}" in field "${fieldName}"`
      );
    }
    const startRaw = segment.slice(0, dashIndex);
    const endRaw = segment.slice(dashIndex + 1);

    if (endRaw.includes("-")) {
      throw new SyntaxError(
        `Ambiguous range "${segment}" in field "${fieldName}": multiple dashes`
      );
    }

    const start = assertInteger(startRaw, fieldName);
    const end = assertInteger(endRaw, fieldName);
    assertInRange(start, min, max, fieldName);
    assertInRange(end, min, max, fieldName);
    return expandRange(start, end, 1, fieldName);
  }

  const value = assertInteger(segment, fieldName);
  assertInRange(value, min, max, fieldName);
  return [value];
}

function parseField(
  raw: string,
  min: number,
  max: number,
  fieldName: string
): number[] {
  const trimmed = raw.trim();
  if (trimmed === "") {
    throw new SyntaxError(`Field "${fieldName}" is empty`);
  }

  const parts = trimmed.split(",");
  if (parts.some((p) => p.trim() === "")) {
    throw new SyntaxError(
      `Field "${fieldName}" contains an empty segment in comma list: "${trimmed}"`
    );
  }

  const valueSet = new Set<number>();
  for (const part of parts) {
    const values = parseSegment(part.trim(), min, max, fieldName);
    for (const v of values) {
      valueSet.add(v);
    }
  }

  return Array.from(valueSet).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronSchedule {
  if (expression === null || expression === undefined) {
    throw new TypeError("Cron expression must be a non-null string");
  }
  if (typeof expression !== "string") {
    throw new TypeError(
      `Cron expression must be a string, got ${typeof expression}`
    );
  }

  const trimmed = expression.trim();
  if (trimmed === "") {
    throw new SyntaxError("Cron expression must not be empty or whitespace");
  }

  const fields = trimmed.split(/\s+/);
  if (fields.length !== 5) {
    throw new SyntaxError(
      `Cron expression must have exactly 5 whitespace-separated fields, got ${fields.length}: "${trimmed}"`
    );
  }

  const result = {} as CronSchedule;

  for (let i = 0; i < FIELD_CONFIGS.length; i++) {
    const { name, min, max } = FIELD_CONFIGS[i];
    result[name] = parseField(fields[i], min, max, name);
  }

  return result;
}

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | Array<unknown> };
type FlatObject = { [key: string]: Primitive };

function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  if (obj === null || typeof obj !== "object" || Array.isArray(obj)) {
    if (prefix) result[prefix] = obj as Primitive;
    return result;
  }

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix) result[prefix] = null;
    return result;
  }

  for (const key of keys) {
    const newKey = prefix ? `${prefix}.${key}` : key;
    const value = obj[key];

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value) &&
      Object.keys(value).length > 0
    ) {
      flattenObject(value as NestedObject, newKey, result);
    } else {
      result[newKey] = Array.isArray(value) ? (value as unknown as Primitive) : (value as Primitive);
    }
  }

  return result;
}

export default flattenObject;

type CronFields = {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
};

const FIELD_CONFIG = [
  { name: "minute" as const, min: 0, max: 59 },
  { name: "hour" as const, min: 0, max: 23 },
  { name: "dayOfMonth" as const, min: 1, max: 31 },
  { name: "month" as const, min: 1, max: 12 },
  // Accept 0–7; both 0 and 7 represent Sunday in many implementations
  { name: "dayOfWeek" as const, min: 0, max: 7 },
] as const;

function buildRange(start: number, end: number, step: number): number[] {
  if (step <= 0) {
    throw new Error(`Step must be a positive integer, got ${step}`);
  }
  if (start > end) {
    throw new Error(`Range start ${start} exceeds end ${end}`);
  }
  const result: number[] = [];
  for (let i = start; i <= end; i += step) {
    result.push(i);
  }
  return result;
}

function assertInBounds(value: number, min: number, max: number, context: string): void {
  if (!Number.isInteger(value) || value < min || value > max) {
    throw new RangeError(`Value ${value} in "${context}" is out of allowed range [${min}–${max}]`);
  }
}

function parseSegment(segment: string, min: number, max: number): number[] {
  if (!segment) {
    throw new Error("Empty segment encountered in cron field");
  }

  // Step expression: "*/N" or "start-end/N"
  const stepSlash = segment.indexOf("/");
  if (stepSlash !== -1) {
    const baseStr = segment.slice(0, stepSlash);
    const stepStr = segment.slice(stepSlash + 1);

    if (!/^\d+$/.test(stepStr)) {
      throw new SyntaxError(`Non-integer step value "${stepStr}" in "${segment}"`);
    }
    const step = parseInt(stepStr, 10);
    if (step <= 0) {
      throw new RangeError(`Step must be >= 1, got ${step} in "${segment}"`);
    }

    if (baseStr === "*") {
      return buildRange(min, max, step);
    }

    // Range base: "start-end/N"
    const dashIdx = baseStr.indexOf("-");
    if (dashIdx < 1) {
      // dashIdx < 1 guards against leading dash (negative numbers)
      throw new SyntaxError(`Invalid base "${baseStr}" in step expression "${segment}"`);
    }
    const start = parseInt(baseStr.slice(0, dashIdx), 10);
    const end = parseInt(baseStr.slice(dashIdx + 1), 10);
    if (!Number.isInteger(start) || !Number.isInteger(end) || isNaN(start) || isNaN(end)) {
      throw new SyntaxError(`Non-integer bounds in "${segment}"`);
    }
    assertInBounds(start, min, max, segment);
    assertInBounds(end, min, max, segment);
    return buildRange(start, end, step);
  }

  // Wildcard: "*"
  if (segment === "*") {
    return buildRange(min, max, 1);
  }

  // Range: "start-end"
  const dashIdx = segment.indexOf("-");
  if (dashIdx > 0) {
    // dashIdx > 0 to reject leading dash (negative numbers)
    const startStr = segment.slice(0, dashIdx);
    const endStr = segment.slice(dashIdx + 1);
    if (!/^\d+$/.test(startStr) || !/^\d+$/.test(endStr)) {
      throw new SyntaxError(`Non-integer range bounds in "${segment}"`);
    }
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);
    assertInBounds(start, min, max, segment);
    assertInBounds(end, min, max, segment);
    if (start > end) {
      throw new RangeError(`Range start ${start} > end ${end} in "${segment}"`);
    }
    return buildRange(start, end, 1);
  }

  // Single integer
  if (/^\d+$/.test(segment)) {
    const value = parseInt(segment, 10);
    assertInBounds(value, min, max, segment);
    return [value];
  }

  throw new SyntaxError(`Unrecognised cron segment "${segment}"`);
}

function parseField(field: string, min: number, max: number, fieldName: string): number[] {
  if (typeof field !== "string" || field.trim() === "") {
    throw new Error(`Empty or missing cron field "${fieldName}"`);
  }

  const parts = field.split(",");
  if (parts.some((p) => p.trim() === "")) {
    throw new SyntaxError(`Trailing or doubled comma in cron field "${fieldName}": "${field}"`);
  }

  const seen = new Set<number>();
  for (const part of parts) {
    const values = parseSegment(part.trim(), min, max);
    for (const v of values) {
      seen.add(v);
    }
  }

  // Return a sorted, deduplicated array
  return Array.from(seen).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronFields {
  if (typeof expression !== "string") {
    throw new TypeError(`parseCron expects a string, received ${typeof expression}`);
  }

  const trimmed = expression.trim();
  if (trimmed === "") {
    throw new Error("Cron expression must not be empty");
  }

  const fields = trimmed.split(/\s+/);
  if (fields.length !== 5) {
    throw new Error(
      `Cron expression must have exactly 5 fields (minute hour dayOfMonth month dayOfWeek), ` +
        `but "${expression}" has ${fields.length}`
    );
  }

  const result = {} as CronFields;
  for (let i = 0; i < FIELD_CONFIG.length; i++) {
    const { name, min, max } = FIELD_CONFIG[i];
    result[name] = parseField(fields[i], min, max, name);
  }

  return result;
}

class LRUCache<T> {
  private readonly capacity: number;
  private readonly cache: Map<string, T>;

  constructor(capacity: number) {
    if (!Number.isInteger(capacity) || capacity < 0) {
      throw new RangeError(`LRUCache capacity must be a non-negative integer, got: ${capacity}`);
    }
    this.capacity = capacity;
    this.cache = new Map<string, T>();
  }

  get(key: string): T | undefined {
    if (key === undefined || key === null) return undefined;
    if (!this.cache.has(key)) return undefined;

    // Promote to most-recently-used by reinserting at tail
    const value = this.cache.get(key) as T;
    this.cache.delete(key);
    this.cache.set(key, value);
    return value;
  }

  set(key: string, value: T): void {
    if (key === undefined || key === null) {
      throw new TypeError(`LRUCache key must not be null or undefined`);
    }
    if (value === undefined) {
      throw new TypeError(`LRUCache value must not be undefined; use delete() to remove entries`);
    }

    // Zero-capacity cache accepts no entries — every write is a no-op
    if (this.capacity === 0) return;

    if (this.cache.has(key)) {
      // Update existing key: remove first so reinsertion moves it to tail
      this.cache.delete(key);
    } else if (this.cache.size >= this.capacity) {
      // Evict the least-recently-used entry (Map head = oldest insertion)
      const lruKey = this.cache.keys().next().value;
      if (lruKey !== undefined) {
        this.cache.delete(lruKey);
      }
    }

    this.cache.set(key, value);
  }

  delete(key: string): boolean {
    return this.cache.delete(key);
  }

  has(key: string): boolean {
    return this.cache.has(key);
  }

  get size(): number {
    return this.cache.size;
  }

  clear(): void {
    this.cache.clear();
  }
}

export default LRUCache;
